import pandas as pd
import numpy as np

class Alpha:
    pass

    @staticmethod
    def alpha_factorminer_vn_001_rank(df, window=100):
        # Tính lợi nhuận đơn giản: close / close.shift(1) - 1
        returns = df['close'] / df['close'].shift(1) - 1
        volume = df.get('matchingVolume', df.get('volume', 1))
        # Tính skewness của volume trong rolling window
        vol_mean = volume.rolling(window).mean()
        vol_std = volume.rolling(window).std(ddof=0).replace(0, np.nan)
        skew_vol = ((volume - vol_mean) ** 3).rolling(window).mean() / (vol_std ** 3 + 1e-9)
        # Điều kiện: nếu returns > 0 thì dùng skew, nếu không thì dùng -skew
        # Thực chất là: sign(returns) * skew
        signal = np.where(returns > 0, skew_vol, -skew_vol)
        signal = pd.Series(signal, index=df.index)
        # Chuẩn hóa Rolling Rank (A)
        signal_rank = signal.rolling(window).rank(pct=True) * 2 - 1
        return signal_rank.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_001_tanh(df, window=100):
        returns = df['close'] / df['close'].shift(1) - 1
        volume = df.get('matchingVolume', df.get('volume', 1))
        vol_mean = volume.rolling(window).mean()
        vol_std = volume.rolling(window).std(ddof=0).replace(0, np.nan)
        skew_vol = ((volume - vol_mean) ** 3).rolling(window).mean() / (vol_std ** 3 + 1e-9)
        signal = np.where(returns > 0, skew_vol, -skew_vol)
        signal = pd.Series(signal, index=df.index)
        # Chuẩn hóa Dynamic Tanh (B)
        signal_std = signal.rolling(window).std().replace(0, np.nan)
        normalized = np.tanh(signal / signal_std)
        return normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_001_zscore(df, window=100):
        returns = df['close'] / df['close'].shift(1) - 1
        volume = df.get('matchingVolume', df.get('volume', 1))
        vol_mean = volume.rolling(window).mean()
        vol_std = volume.rolling(window).std(ddof=0).replace(0, np.nan)
        skew_vol = ((volume - vol_mean) ** 3).rolling(window).mean() / (vol_std ** 3 + 1e-9)
        signal = np.where(returns > 0, skew_vol, -skew_vol)
        signal = pd.Series(signal, index=df.index)
        # Chuẩn hóa Rolling Z-Score Clip (C)
        sig_mean = signal.rolling(window).mean()
        sig_std = signal.rolling(window).std(ddof=0).replace(0, np.nan)
        normalized = ((signal - sig_mean) / sig_std).clip(-1, 1)
        return normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_001_sign(df, window=80):
        returns = df['close'] / df['close'].shift(1) - 1
        volume = df.get('matchingVolume', df.get('volume', 1))
        vol_mean = volume.rolling(window).mean()
        vol_std = volume.rolling(window).std(ddof=0).replace(0, np.nan)
        skew_vol = ((volume - vol_mean) ** 3).rolling(window).mean() / (vol_std ** 3 + 1e-9)
        signal = np.where(returns > 0, skew_vol, -skew_vol)
        signal = pd.Series(signal, index=df.index)
        # Chuẩn hóa Sign/Binary (D)
        normalized = np.sign(signal)
        return normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_001_wf(df, p1=0.3, p2=100):
        returns = df['close'] / df['close'].shift(1) - 1
        volume = df.get('matchingVolume', df.get('volume', 1))
        vol_mean = volume.rolling(p2).mean()
        vol_std = volume.rolling(p2).std(ddof=0).replace(0, np.nan)
        skew_vol = ((volume - vol_mean) ** 3).rolling(p2).mean() / (vol_std ** 3 + 1e-9)
        signal = np.where(returns > 0, skew_vol, -skew_vol)
        signal = pd.Series(signal, index=df.index)
        # Chuẩn hóa Winsorized Fisher (E)
        low = signal.rolling(p2).quantile(p1)
        high = signal.rolling(p2).quantile(1 - p1)
        winsorized = signal.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_002_rank(df, window=100):
        returns = df['close'].pct_change().fillna(0)
        volume = df.get('matchingVolume', df.get('volume', 1))
        raw = -((volume * returns).rolling(window).corr(df['close']))
        signal = raw.fillna(0).replace([np.inf, -np.inf], 0)
        signal = (signal.rolling(window).rank(pct=True) * 2) - 1
        return -signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_002_tanh(df, window=25):
        returns = df['close'].pct_change().fillna(0)
        volume = df.get('matchingVolume', df.get('volume', 1))
        raw = -((volume * returns).rolling(window).corr(df['close']))
        signal = raw.fillna(0).replace([np.inf, -np.inf], 0)
        signal = np.tanh(signal / (signal.rolling(window).std().replace(0, np.nan)))
        return signal.fillna(0)

