    @staticmethod
    def alpha_factorminer_vn_009_rank(df, window=80):
        high = df['high'].values
        low = df['low'].values
        close = df['close'].values
        length = len(df)

        # Calculate True Range (ATR components)
        tr = np.maximum(high[1:], close[:-1]) - np.minimum(low[1:], close[:-1])
        tr = np.concatenate([[np.nan], tr])
        atr_series = pd.Series(tr, index=df.index)
        atr = atr_series.rolling(window, min_periods=window).mean()

        # Calculate raw signal: (high - low) / atr
        raw = (df['high'] - df['low']) / atr.replace(0, np.nan)

        # Z-score normalization
        zscore = ((raw - raw.rolling(window, min_periods=window).mean()) / raw.rolling(window, min_periods=window).std()).replace([np.inf, -np.inf], 0)

        # Negate the zscore
        neg_zscore = -zscore

        # Rolling Rank normalization (Case A)
        normalized = (neg_zscore.rolling(window, min_periods=window).rank(pct=True) * 2) - 1

        result = normalized.fillna(0)
        return -result

