    @staticmethod
    def alpha_factorminer_vn_014_k(df, window=5):
        close = df['close']
        high = df['high']
        low = df['low']
        hma_length = window
        ts_length = window

        hma = (2 * close.rolling(hma_length).mean() - close.rolling(hma_length // 2).mean())

        ts_min = low.rolling(ts_length).min()
        ts_max = high.rolling(ts_length).max()
        denominator = ts_max - ts_min
        denominator = denominator.replace(0, np.nan)

        numerator = hma - ts_min
        raw = numerator / denominator
        raw = raw.ffill().fillna(0)

        result = -(-raw)

        normalized = (result.rolling(window).rank(pct=True) * 2) - 1
        normalized = normalized.ffill().fillna(0)

        return -normalized

