        cokurt = ((returns - mean_r) ** 2 * (volume - mean_v) ** 2).rolling(window).mean() / (cross_var ** 2 + 1e-9)
        raw = -cokurt
        # Dynamic Tanh
        normalized = np.tanh(raw / (raw.rolling(window).std() + 1e-9))
        return -normalized.fillna(0)

