    @staticmethod
    def alpha_factorminer_vn_021_wf(df, window_1=100, window_2=3, p1=0.05, p2=30):
        # Hardcode additional params p1, p2 inside function
        # Step 1: Compute residual of volume regressed on close
        x = df['close']
        y = df['matchingVolume']
        y_mean = y.rolling(window_1).mean()
        x_mean = x.rolling(window_1).mean()
        cov = (y * x).rolling(window_1).mean() - y_mean * x_mean
        var_x = (x ** 2).rolling(window_1).mean() - x_mean ** 2
        beta = cov / var_x.replace(0, np.nan)
        residual = y - beta * x
        # Step 2
        ret = df['close'].pct_change()
        ret_mean = ret.rolling(window_2).mean()
        res_mean = residual.rolling(window_2).mean()
        cov2 = (residual * ret).rolling(window_2).mean() - res_mean * ret_mean
        var_ret = (ret ** 2).rolling(window_2).mean() - ret_mean ** 2
        reg_beta = cov2 / var_ret.replace(0, np.nan)
        raw = -reg_beta
        # Normalize: Winsorized Fisher (param p1, p2 hardcoded)
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        # Fisher transform
        numerator = (winsorized - low) / (high - low + 1e-9)
        clamped = numerator * 1.98 - 0.99
        clamped = clamped.clip(-0.9999, 0.9999)
        result = np.arctanh(clamped)
        result = result.fillna(0)
        return -result

    @staticmethod
    def alpha_factorminer_vn_022_rank(df, window=60, sub_window=1):
        close = df['close']
        bollinger_mid = close.rolling(window).mean()
        bollinger_std = close.rolling(window).std()
        bollinger_range = (bollinger_mid + 2 * bollinger_std) - (bollinger_mid - 2 * bollinger_std)
        pct_change = close.pct_change(sub_window)
        raw = -(bollinger_range / pct_change.replace(0, np.nan))
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.ffill().fillna(0)

