    @staticmethod
    def alpha_factorminer_vn_026_p(df, window_29=100, window_13=40):
        volume = df['matchingVolume'] if 'matchingVolume' in df.columns else df.get('volume', 1)
        rolling_mean_29 = volume.rolling(window_29).mean()
        rolling_std_29 = volume.rolling(window_29).std().replace(0, np.nan)
        robust_z_volume = (volume - rolling_mean_29) / rolling_std_29
        days = pd.Series(np.arange(len(df)), index=df.index)
