    @staticmethod
    def alpha_factorminer_vn_035_rank(df, window=19):
        close = df['close']
        volume = df['matchingVolume']
        sc = 2.0 / (window + 1)
        er = (close - close.shift(window)).abs() / (close.diff().abs().rolling(window).sum() + 1e-9)
        fast_sc = 2.0 / 3.0
        slow_sc = 2.0 / 31.0
        kama_sc = (er * (fast_sc - slow_sc) + slow_sc) ** 2
        kama = volume.ewm(alpha=kama_sc, adjust=False).mean()
        pct_chg = kama.pct_change(3)
        neg1 = -pct_chg
        neg2 = -neg1
        return (neg2.rolling(window).rank(pct=True) * 2) - 1

