    @staticmethod
    def alpha_factorminer_vn_040_rank(df, window_rank=35):
        raw = pd.Series(np.nan, index=df.index)
        x = np.arange(29)
        for i in range(29, len(df)):
            y = df['matchingVolume'].iloc[i-29:i].values
            if np.isnan(y).sum() > 0:
                continue
            A = np.vstack([x, np.ones(29)]).T
            coeff, _, _, _ = np.linalg.lstsq(A, y, rcond=None)
            resid = y - (coeff[0]*x + coeff[1])
            raw.iloc[i] = resid[-1]
        raw = raw.fillna(0)
        x2 = np.arange(11)
        slope_raw = pd.Series(np.nan, index=df.index)
        for i in range(10, len(df)):
            y2 = raw.iloc[i-10:i+1].values
            if np.isnan(y2).sum() > 0:
                continue
            A2 = np.vstack([x2, np.ones(11)]).T
            coeff2, _, _, _ = np.linalg.lstsq(A2, y2, rcond=None)
            slope_raw.iloc[i] = coeff2[0]
        slope_raw = slope_raw.fillna(0)
        normalized = (slope_raw.rolling(window_rank, min_periods=1).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

