        median_low = df['low'].rolling(window).median()
        raw = -(median_high - median_low)
        low = raw.rolling(window).quantile(quantile)
        high = raw.rolling(window).quantile(1 - quantile)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
