    @staticmethod
    def alpha_factorminer_vn_055_rank(df, window=80, sub_window=7):
        close = df['close']
        volume = df['matchingVolume']
        ret = close.pct_change()
        log_ret = np.log1p((close / close.shift(1)) - 1).fillna(0)
        # Ulcer Index on volume
        max_vol = volume.rolling(window).max()
        percent_drawdown = (volume - max_vol) / (max_vol + 1e-9) * 100
        ulcer_vol = np.sqrt((percent_drawdown ** 2).rolling(window).mean()).fillna(0)
        mean_ulcer = ulcer_vol.rolling(sub_window).mean()
        condition = ulcer_vol > mean_ulcer
        raw = pd.Series(np.where(condition, -volume, volume), index=df.index)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

