    @staticmethod
    def alpha_factorminer_vn_061_rank(df, window=15):
        # Tính MACD cho high và low
        high_12 = df['high'].ewm(span=12, adjust=False).mean()
        high_26 = df['high'].ewm(span=26, adjust=False).mean()
        macd_high = high_12 - high_26
        low_12 = df['low'].ewm(span=12, adjust=False).mean()
        low_26 = df['low'].ewm(span=26, adjust=False).mean()
        macd_low = low_12 - low_26
        # Regression residual: y = macd_high, x = macd_low
        y = macd_high
        x = macd_low
        # Tính slope và intercept dùng rolling covariance/var
        x_mean = x.rolling(window=window).mean()
        y_mean = y.rolling(window=window).mean()
        cov = (x * y).rolling(window=window).mean() - x_mean * y_mean
        var_x = (x ** 2).rolling(window=window).mean() - x_mean ** 2
        slope = cov / var_x.replace(0, np.nan)
        intercept = y_mean - slope * x_mean
        residual = y - (slope * x + intercept)
        raw = -residual.fillna(0)
        # Chuẩn hóa Rolling Rank
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_061_tanh(df, window=10):
        high_12 = df['high'].ewm(span=12, adjust=False).mean()
        high_26 = df['high'].ewm(span=26, adjust=False).mean()
        macd_high = high_12 - high_26
        low_12 = df['low'].ewm(span=12, adjust=False).mean()
        low_26 = df['low'].ewm(span=26, adjust=False).mean()
        macd_low = low_12 - low_26
        y = macd_high
        x = macd_low
        x_mean = x.rolling(window=window).mean()
        y_mean = y.rolling(window=window).mean()
        cov = (x * y).rolling(window=window).mean() - x_mean * y_mean
        var_x = (x ** 2).rolling(window=window).mean() - x_mean ** 2
        slope = cov / var_x.replace(0, np.nan)
        intercept = y_mean - slope * x_mean
        residual = y - (slope * x + intercept)
        raw = -residual.fillna(0)
        # Chuẩn hóa Dynamic Tanh
        std_raw = raw.rolling(window).std().replace(0, np.nan)
        normalized = np.tanh(raw / std_raw)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_061_zscore(df, window=5):
        high_12 = df['high'].ewm(span=12, adjust=False).mean()
        high_26 = df['high'].ewm(span=26, adjust=False).mean()
        macd_high = high_12 - high_26
        low_12 = df['low'].ewm(span=12, adjust=False).mean()
        low_26 = df['low'].ewm(span=26, adjust=False).mean()
        macd_low = low_12 - low_26
        y = macd_high
        x = macd_low
        x_mean = x.rolling(window=window).mean()
        y_mean = y.rolling(window=window).mean()
        cov = (x * y).rolling(window=window).mean() - x_mean * y_mean
        var_x = (x ** 2).rolling(window=window).mean() - x_mean ** 2
        slope = cov / var_x.replace(0, np.nan)
        intercept = y_mean - slope * x_mean
        residual = y - (slope * x + intercept)
        raw = -residual.fillna(0)
        # Chuẩn hóa Rolling Z-Score/Clip
        mean_raw = raw.rolling(window).mean()
        std_raw = raw.rolling(window).std().replace(0, np.nan)
        normalized = ((raw - mean_raw) / std_raw).clip(-1, 1)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_061_sign(df, window=10):
        high_12 = df['high'].ewm(span=12, adjust=False).mean()
