    @staticmethod
    def alpha_factorminer_vn_061_wf(df, window=20, p1=0.1):
        high_12 = df['high'].ewm(span=12, adjust=False).mean()
        high_26 = df['high'].ewm(span=26, adjust=False).mean()
        macd_high = high_12 - high_26
        low_12 = df['low'].ewm(span=12, adjust=False).mean()
        low_26 = df['low'].ewm(span=26, adjust=False).mean()
        macd_low = low_12 - low_26
        y = macd_high
        x = macd_low
        x_mean = x.rolling(window=window).mean()
        y_mean = y.rolling(window=window).mean()
        cov = (x * y).rolling(window=window).mean() - x_mean * y_mean
        var_x = (x ** 2).rolling(window=window).mean() - x_mean ** 2
        slope = cov / var_x.replace(0, np.nan)
        intercept = y_mean - slope * x_mean
        residual = y - (slope * x + intercept)
        raw = -residual.fillna(0)
        # Chuẩn hóa Winsorized Fisher
        low_val = raw.rolling(window=window).quantile(p1)
        high_val = raw.rolling(window=window).quantile(1 - p1)
        clipped = raw.clip(lower=low_val, upper=high_val, axis=0)
        denominator = (high_val - low_val).replace(0, np.nan)
        normalized = np.arctanh(((clipped - low_val) / denominator) * 1.98 - 0.99)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_062_rank(df, window=100):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        volume = df.get('matchingVolume', df.get('volume', 1))
        entropy_ratio = (vwap / vwap.rolling(window).sum()).replace(0, np.nan)
        entropy_vwap = - (entropy_ratio * np.log(entropy_ratio + 1e-9)).rolling(window).sum()
        vol_ratio = (volume / volume.rolling(window).sum()).replace(0, np.nan)
        entropy_vol = - (vol_ratio * np.log(vol_ratio + 1e-9)).rolling(window).sum()
        raw = entropy_vol - entropy_vwap
        zscore = (raw - raw.rolling(window).mean()) / raw.rolling(window).std().replace(0, np.nan)
        raw_neg = -zscore
        result = (raw_neg.rolling(window).rank(pct=True) * 2) - 1
        return result.fillna(0)

