        vol_ratio = (volume / volume.rolling(window).sum()).replace(0, np.nan)
        entropy_vol = - (vol_ratio * np.log(vol_ratio + 1e-9)).rolling(window).sum()
        raw = entropy_vol - entropy_vwap
        zscore = (raw - raw.rolling(window).mean()) / raw.rolling(window).std().replace(0, np.nan)
        raw_neg = -zscore
        low = raw_neg.rolling(window).quantile(winsor_quantile)
        high = raw_neg.rolling(window).quantile(1 - winsor_quantile)
        winsorized = raw_neg.clip(lower=low, upper=high, axis=0)
        result = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
