    @staticmethod
    def alpha_factorminer_vn_063_rank(df, window=15):
        close = df['close']
        tsrank = close.rolling(window).rank(pct=True)
        median = close.rolling(window).median().ffill()
        median_normalized = (median - close.rolling(window).min()) / (close.rolling(window).max() - close.rolling(window).min() + 1e-9)
        sub = tsrank - median_normalized
        neg = -sub
        return -(neg.rolling(window).rank(pct=True) * 2) - 1

