    @staticmethod
    def alpha_factorminer_vn_065_rank(df, window=60, sub_window=5):
        volume = df.get('matchingVolume', df.get('volume', df['close'] * 0.01))
        hma_window = 17
        beta_period = sub_window
        half = int(hma_window / 2)
        sqrt_half = int(np.sqrt(half))
        wma_half = volume.rolling(half).apply(lambda x: np.average(x, weights=np.arange(1, len(x)+1)), raw=True)
        wma_full = volume.rolling(hma_window).apply(lambda x: np.average(x, weights=np.arange(1, len(x)+1)), raw=True)
        raw_hma = 2 * wma_half - wma_full
        hma = raw_hma.rolling(sqrt_half).apply(lambda x: np.average(x, weights=np.arange(1, len(x)+1)), raw=True)
        resi = volume - hma
        resi = resi.rolling(window).apply(lambda x: np.polyfit(np.arange(len(x)), x, 1)[1] if len(x) == window else np.nan, raw=True)
        resi_regbeta = df['close'].rolling(beta_period).apply(lambda x: np.polyfit(np.arange(len(x)), x, 1)[0] if len(x) == beta_period else np.nan, raw=True)
        raw = -1 * resi_regbeta
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result.fillna(0)

