    @staticmethod
    def alpha_factorminer_vn_073_wf(df, window=40, count_window=40, quantile=0.1):
        v = df.get('matchingVolume', df.get('volume', 1))
        a = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        nan_count = v.rolling(count_window).apply(lambda x: pd.isna(x).sum(), raw=False)
        nan_count = pd.Series(nan_count, index=df.index)
        series = pd.Series(np.where(nan_count > 5, a, v), index=df.index)
        s_mean = series.rolling(window).mean()
        c_mean = df['close'].rolling(window).mean()
        cov = ((series - s_mean) * (df['close'] - c_mean)).rolling(window).mean()
        var_c = df['close'].rolling(window).var(ddof=0)
        var_c = var_c.replace(0, np.nan)
        beta = cov / var_c
        raw = -beta
        # Normalize: Winsorized Fisher (E)
        p2 = window
        p1 = quantile
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        # Compute normalized value
        numerator = winsorized - low
        denominator = high - low
        denominator = denominator.replace(0, np.nan)
        # Avoid division by zero and extreme values
        normalized = np.arctanh(((numerator / denominator) * 1.98 - 0.99).clip(-0.99, 0.99))
        result = normalized.fillna(0)
        return result

    @staticmethod
    def alpha_factorminer_vn_074_rank(df, window=60):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        cumsum = np.log1p(amt).cumsum()
        mad = (cumsum - cumsum.rolling(window).mean()).abs().rolling(window).mean()
        raw = -(cumsum - cumsum.rolling(window).mean()) / mad.replace(0, np.nan)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

