    @staticmethod
    def alpha_factorminer_vn_078_rank(df, window=17):
        volume = df.get('matchingVolume', df.get('volume', 1))
        volume = np.maximum(volume, 0)
        var_perc = volume.rolling(window).quantile(0.1)
        count_high = volume.rolling(window).apply(lambda x: np.sum(x > volume.shift().rolling(window).quantile(0.5)), raw=False)
        # Simplify: use count above median
        median_vol = volume.rolling(window).median()
        count_above_median = (volume > median_vol).rolling(window).sum()
        cond = count_above_median > 10
        raw = pd.Series(np.where(cond, var_perc, -var_perc), index=df.index)
        raw = -raw
        # Normalize A: Rolling Rank
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return result.fillna(0)

