    @staticmethod
    def alpha_factorminer_vn_079_rank(df, window=5):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        # Linear regression residuals: close vs vwap over 19 periods
        x = pd.Series(np.arange(19), index=df.index[-19:] if len(df) >= 19 else df.index)
        # For vectorized rolling, expand x to full length
        n = len(df)
        x_full = pd.Series(np.tile(np.arange(19), int(np.ceil(n / 19)))[:n], index=df.index)
        cov = df['close'].rolling(19).cov(x_full)
        var = x_full.rolling(19).var().replace(0, np.nan)
        slope = cov / var
        intercept = df['close'].rolling(19).mean() - slope * x_full.rolling(19).mean()
        resi = df['close'] - (slope * x_full + intercept)
        # Rolling slope of residuals over window
        cov_resi = resi.rolling(window).cov(x_full)
        var_resi = x_full.rolling(window).var().replace(0, np.nan)
        slope_resi = cov_resi / var_resi
        raw = -slope_resi
        # Normalization A
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        result = result.ffill().fillna(0)
        return -result

