    @staticmethod
    def alpha_factorminer_vn_083_rank(df, window=60):
        high = df['high']
        low = df['low']
        close = df['close']
        # Calculate ATR manually without using future data
        tr = pd.concat([high - low, (high - close.shift(1)).abs(), (low - close.shift(1)).abs()], axis=1).max(axis=1)
        atr = tr.rolling(window=window, min_periods=1).mean()
        mean_atr = atr.rolling(window=window, min_periods=1).mean()
        returns = close.pct_change()
        raw = -pd.Series(np.where(atr > mean_atr, returns, -returns), index=df.index)
        # Normalization method A: Rolling Rank
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = signal.ffill().fillna(0)
        return -signal

