    @staticmethod
    def alpha_factorminer_vn_088_8(df, window=25):
        close = df['close']
        returns = close.pct_change()
        x = pd.Series(np.arange(len(df)), index=df.index)
        y = returns
        cov = y.rolling(window).cov(x)
        var = x.rolling(window).var().replace(0, np.nan)
        slope = cov / var
        intercept = y.rolling(window).mean() - slope * x.rolling(window).mean()
        raw = intercept / (np.abs(slope) + 1.0)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = normalized.fillna(0)
        return -signal

