    @staticmethod
    def alpha_factorminer_vn_090_rank(df, window=5):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = df['close'].pct_change().fillna(0)
        volume = df['matchingVolume']
        # CoSkew($returns, $volume, 37): use rolling cov of returns with squared volume
        vol_sq = volume ** 2
        mean_ret = returns.rolling(window).mean()
        mean_vol_sq = vol_sq.rolling(window).mean()
        cov = (returns * vol_sq).rolling(window).mean() - mean_ret * mean_vol_sq
        var_ret = returns.rolling(window).var().replace(0, np.nan)
        var_vol_sq = vol_sq.rolling(window).var().replace(0, np.nan)
        coskew = cov / (var_ret * var_vol_sq).pow(0.5)
        raw = vwap * coskew
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = -normalized
        return -signal.fillna(0)

