    @staticmethod
    def alpha_factorminer_vn_091_rank(df, window=10):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        ema12 = close.ewm(span=12, adjust=False).mean()
        ema26 = close.ewm(span=26, adjust=False).mean()
        macd = ema12 - ema26
        x = macd
        y = vwap
        x_mean = x.rolling(window).mean()
        y_mean = y.rolling(window).mean()
        cov = ((x - x_mean) * (y - y_mean)).rolling(window).mean()
        var_x = ((x - x_mean) ** 2).rolling(window).mean().replace(0, np.nan)
        beta = cov / var_x
        resid = y - beta * x
        raw = -resid
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

