    @staticmethod
    def alpha_factorminer_vn_092_rank(df, window=20):
        close = df['close']
        rets = close.pct_change(fill_method=None).replace([np.inf, -np.inf], np.nan)
        rets = rets.ffill().fillna(0)
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope = rets.rolling(window).cov(days) / days.rolling(window).var().replace(0, np.nan)
        slope = slope.ffill().fillna(0)
        p = rets / rets.rolling(window).sum().replace(0, np.nan)
        p = p.ffill().fillna(0)
        log_p = np.log(p.clip(lower=1e-10))
        entropy = -(p * log_p).rolling(window).sum().fillna(0)
        raw = -slope * entropy
        norm = (raw.rolling(window).rank(pct=True) * 2) - 1
        norm = norm.ffill().fillna(0)
        return norm

