        z_vwap = ((vwap - mean_vwap) / std_vwap).fillna(0)
        z_vol = ((volume - mean_vol) / std_vol).fillna(0)
        cokurt = (z_vwap**3 * z_vol).rolling(window).mean() / (std_vwap * std_vol + 1e-9)
        condition = cokurt > 0
        raw_signal = pd.Series(np.where(condition, returns, -returns), index=df.index)
        final = -(raw_signal)
        return np.tanh(final / final.rolling(norm_window).std().replace(0, 1e-9))

