        ema_low = low.ewm(span=window, adjust=False).mean()
        ratio = ema_high / ema_low.replace(0, np.nan)
        raw = ratio.pct_change(periods=2).replace([np.inf, -np.inf], np.nan)
        raw = raw.ffill().fillna(0)
