    @staticmethod
    def alpha_factorminer_vn_107_rank(df, window=50, rank_window=40):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        daily_ret = df['close'].pct_change().fillna(0)
        # Tính CoSkew từ daily returns của amt và vwap (không lookahead bias)
        coskew = (amt * vwap).rolling(window=window).corr((amt**2).rolling(window=window).mean().replace(0, np.nan)).fillna(0)
        # Sản phẩm trung gian: coskew>0 thì cs_neutralize(-ret), else -(-ret) = ret
        signal = pd.Series(index=df.index, dtype=float)
        pos_mask = coskew > 0
        # CsNeutralize trên returns (trừ đi cross-sectional mean)
        cs_mean = daily_ret.mean()
        cs_neutralized_ret = daily_ret - cs_mean
        neg_cs_neutralized_ret = -cs_neutralized_ret
        # Nếu coskew>0: signal=cs_neutralized_ret, else signal=-(-cs_neutralized_ret)=cs_neutralized_ret
        signal = pd.Series(np.where(pos_mask, cs_neutralized_ret, -cs_neutralized_ret), index=df.index)
        # Áp dụng dấu âm từ Neg(IfElse(...))
        signal = -signal
        # Chuẩn hóa Rolling Rank
        raw = signal
        normalized = (raw.rolling(rank_window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_107_tanh(df, window=100):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = df['close'].pct_change().fillna(0)

        # Calculate CoSkew using rolling moments
        mean_amt = amt.rolling(window).mean()
        mean_vwap = vwap.rolling(window).mean()
        std_amt = amt.rolling(window).std()
        std_vwap = vwap.rolling(window).std()

        coskew_raw = ((amt - mean_amt) * (vwap - mean_vwap) ** 2).rolling(window).mean() / (std_amt * std_vwap ** 2 + 1e-9)
        coskew_raw = coskew_raw.fillna(0)

        condition = coskew_raw > 0
        neutralized_returns = returns - returns.rolling(window).mean()

        result = pd.Series(np.where(condition, neutralized_returns, -neutralized_returns), index=df.index)
        raw_signal = -result

        # Normalization: Dynamic Tanh (Case B)
        normalized = np.tanh(raw_signal / (raw_signal.rolling(window).std() + 1e-9))
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_107_zscore(df, window=100):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = df['close'].pct_change().fillna(0)

        mean_amt = amt.rolling(window).mean()
        mean_vwap = vwap.rolling(window).mean()
        std_amt = amt.rolling(window).std()
        std_vwap = vwap.rolling(window).std()

        coskew_raw = ((amt - mean_amt) * (vwap - mean_vwap) ** 2).rolling(window).mean() / (std_amt * std_vwap ** 2 + 1e-9)
        coskew_raw = coskew_raw.fillna(0)

        condition = coskew_raw > 0
        neutralized_returns = returns - returns.rolling(window).mean()

        result = pd.Series(np.where(condition, neutralized_returns, -neutralized_returns), index=df.index)
        raw_signal = -result

        # Normalization: Rolling Z-Score Clip (Case C)
        normalized = ((raw_signal - raw_signal.rolling(window).mean()) / (raw_signal.rolling(window).std() + 1e-9)).clip(-1, 1)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_107_sign(df, window=50):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = df['close'].pct_change().fillna(0)

        mean_amt = amt.rolling(window).mean()
        mean_vwap = vwap.rolling(window).mean()
        std_amt = amt.rolling(window).std()
        std_vwap = vwap.rolling(window).std()

        coskew_raw = ((amt - mean_amt) * (vwap - mean_vwap) ** 2).rolling(window).mean() / (std_amt * std_vwap ** 2 + 1e-9)
        coskew_raw = coskew_raw.fillna(0)

        condition = coskew_raw > 0
        neutralized_returns = returns - returns.rolling(window).mean()

        result = pd.Series(np.where(condition, neutralized_returns, -neutralized_returns), index=df.index)
        raw_signal = -result

        # Normalization: Sign/Binary Soft (Case D)
        normalized = np.sign(raw_signal)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_107_wf(df, window=100, p1=0.1):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = df['close'].pct_change().fillna(0)

        mean_amt = amt.rolling(window).mean()
        mean_vwap = vwap.rolling(window).mean()
        std_amt = amt.rolling(window).std()
        std_vwap = vwap.rolling(window).std()

        coskew_raw = ((amt - mean_amt) * (vwap - mean_vwap) ** 2).rolling(window).mean() / (std_amt * std_vwap ** 2 + 1e-9)
        coskew_raw = coskew_raw.fillna(0)

        condition = coskew_raw > 0
        neutralized_returns = returns - returns.rolling(window).mean()

        result = pd.Series(np.where(condition, neutralized_returns, -neutralized_returns), index=df.index)
        raw_signal = -result

        # Normalization: Winsorized Fisher (Case E)
        p2 = window
        low = raw_signal.rolling(p2).quantile(p1)
        high = raw_signal.rolling(p2).quantile(1 - p1)
        winsorized = raw_signal.clip(lower=low, upper=high)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_108_rank(df, window=75):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = df['close'].pct_change()
        # UlcerIndex calculation: sqrt(mean(squared drawdowns)) / mean? Actually standard: sqrt(mean of squared percentage drawdowns from peak)
        # Here: UlcerIndex(vwap, 29) > 0.5 condition
        peak = vwap.rolling(29).max()
        drawdown = (vwap - peak) / peak
        ulcer = np.sqrt((drawdown**2).rolling(29).mean())
        # RegBeta(vwap, returns, 31) using covariance/var
        beta = vwap.rolling(window).cov(returns) / returns.rolling(window).var().replace(0, np.nan)
        # IfElse: if ulcer > 0.5 then beta else -beta
        condition = ulcer > 0.5
        raw = pd.Series(np.where(condition, beta, -beta), index=df.index)
        # Neg(Neg(x)) = x
        raw = raw  # Neg(Neg) cancels out
        # Normalize using Rolling Rank
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        normalized = normalized.ffill().fillna(0)
        return -normalized

