    @staticmethod
    def alpha_factorminer_vn_109_wf(df, window=40, p1=0.9):
        close = df['close']
        dema_7 = 2 * close.ewm(span=7, adjust=False).mean() - close.ewm(span=7, adjust=False).mean().ewm(span=7, adjust=False).mean()
        cumprod_dema = (1 + dema_7.pct_change()).fillna(1).rolling(window=window, min_periods=1).apply(lambda x: np.prod(x), raw=True)
        tsmax_close = close.rolling(window=37, min_periods=1).max()
        raw = cumprod_dema / tsmax_close
        raw = -raw
        p2 = raw.rolling(window*4, min_periods=1).quantile(0.95).notna().sum() if len(raw) > 0 else 20
        p2 = max(20, int(p2 * 0.2))
        low = raw.rolling(window=p2, min_periods=1).quantile(p1)
        high = raw.rolling(window=p2, min_periods=1).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        range_ = (high - low).replace(0, 1e-9)
        normalized = np.arctanh(((winsorized - low) / (range_ + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0)

