    @staticmethod
    def alpha_factorminer_vn_111_rank(df, window=100):
        # Decay:CumSum Volume with half-life decay factor 5
        volume = df['matchingVolume'].fillna(df.get('volume', 0))
        returns = df['close'].pct_change().fillna(0)
        decay_factor = 0.5 ** (5 / 5)  # Hardcode decay parameter = 5
        # Use ewm with adjust=False to implement decay cumsum: weight decays exponentially
        # We need a simple decay weight: linear or exponential? The original seems exponential half-life = 5
        # Use ewm(alpha=1-0.5^(1/5)) to get half-life 5
        halflife = 5
        alpha = 1 - 0.5 ** (1/halflife)
        decay_volume = volume.ewm(alpha=alpha, adjust=False).mean()
        # Neg(Corr(decay_volume, returns, 11))
        corr_val = decay_volume.rolling(window).corr(returns)
        # Neg(Neg(...)) = corr
        raw = corr_val
        # Normalization A: Rolling Rank
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

