    @staticmethod
    def alpha_factorminer_vn_122_rank(df, window_ui=40, window_mean=30):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', 1))
        ret = df['close'].pct_change()
        rolling_max = amt.rolling(window_ui).max()
        pct_dd = (amt - rolling_max) / rolling_max.replace(0, np.nan)
        ulcer = np.sqrt((pct_dd ** 2).rolling(window_ui).mean())
        ui = ulcer.rolling(window_mean).mean()
        rank_ui = ui.rank(pct=True)
        condition = rank_ui > 0.5
        rank_ret = ret.rank(pct=True)
        raw = pd.Series(np.where(condition, 2 * rank_ret - 1, -(2 * rank_ret - 1)), index=df.index)
        raw = raw.ffill().fillna(0)
        signal = (raw.rolling(window_ui).rank(pct=True) * 2) - 1
        return -signal

