    @staticmethod
    def alpha_factorminer_vn_129_rank(df, window=10, decay_window=30):
        close = df['close']
        ret = df['close'].pct_change()
        bollinger_mid = close.rolling(window).mean()
        bollinger_std = close.rolling(window).std()
        bollinger_range = (close - bollinger_mid + bollinger_std) / (bollinger_std * 2 + 1e-9)
        cond = ret > 0
        raw = pd.Series(np.where(cond, bollinger_range, -bollinger_range), index=df.index)
        alpha = raw.ewm(span=decay_window, adjust=False).mean()
        zscore = (alpha - alpha.rolling(decay_window).mean()) / alpha.rolling(decay_window).std().replace(0, np.nan)
        neg_alpha = -zscore
        result = (neg_alpha.rolling(decay_window).rank(pct=True) * 2) - 1
        return -result.fillna(0)

