    @staticmethod
    def alpha_factorminer_vn_133_rank(df, window_rank=5):
        # Calculate KAMA
        kama_period = 13
        close = df['close']
        # Efficiency Ratio
        change = close.diff(kama_period)
        volatility = close.diff().abs().rolling(kama_period).sum()
        er = (change / volatility.replace(0, np.nan)).fillna(0)
        # Fast and Slow smoothing constants
        fast_sc = 2 / (2 + 1)
        slow_sc = 2 / (30 + 1)
        sc = (er * (fast_sc - slow_sc) + slow_sc) ** 2
        # KAMA
        kama = close.copy()
        for i in range(kama_period, len(kama)):
            kama.iloc[i] = kama.iloc[i-1] + sc.iloc[i] * (close.iloc[i] - kama.iloc[i-1])
        # Calculate VWAP (if not available)
        vwap_col = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        # Regression Residual: RegResi($vwap, KAMA($close, 13), 19)
        y = vwap_col
        x = kama
        cov = y.rolling(19).cov(x)
        var_x = x.rolling(19).var().replace(0, np.nan)
        slope = cov / var_x
        intercept = y.rolling(19).mean() - slope * x.rolling(19).mean()
        resi = y - (slope * x + intercept)
        # TsLinRegSlope on residual over 7 periods (slope is same as before)
        y_slope = resi
        x_slope = pd.Series(np.arange(len(df)), index=df.index)
        cov_slope = y_slope.rolling(window_rank).cov(x_slope)
        var_x_slope = x_slope.rolling(window_rank).var().replace(0, np.nan)
        slope_final = cov_slope / var_x_slope
        # Negation
        raw = -slope_final
        # Normalization: Rolling Rank (A)
        normalized = (raw.rolling(window_rank).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

