    @staticmethod
    def alpha_factorminer_vn_134_rank(df, window=15):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        amt = df.get('amount', df['close'] * df.get('matchingVolume', 1))
        returns = df['close'].pct_change(fill_method=None)
        returns_mean = vwap.rolling(window).mean()
        returns_std = vwap.rolling(window).std()
        coKurt = pd.Series(np.zeros(len(df)), index=df.index)
        for i in range(window, len(df)):
            x = vwap.iloc[i-window:i]
            y = amt.iloc[i-window:i]
            if x.std() > 0 and y.std() > 0:
                x_std = (x - x.mean()) / x.std()
                y_std = (y - y.mean()) / y.std()
                coKurt.iloc[i] = np.mean(x_std * y_std ** 3)
        raw = np.where(returns > 0, -coKurt, coKurt)
        raw = pd.Series(raw, index=df.index)
        result = raw.rolling(window).rank(pct=True) * 2 - 1
        return result.fillna(0)

