    @staticmethod
    def alpha_factorminer_vn_141_rank(df, window=10, sub_window=40):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        # KAMA calculation with vectorized smoothing
        price = vwap
        kama_window = window
        fast = 2 / (2 + 1)
        slow = 2 / (30 + 1)
        change = price.diff(kama_window).abs()
        volatility = price.diff().abs().rolling(kama_window).sum()
        efficiency_ratio = change / (volatility + 1e-9)
        smoothing_constant = (efficiency_ratio * (fast - slow) + slow) ** 2
        # Use pandas ewm with alpha vector
        kama = pd.Series(np.nan, index=df.index)
        kama.iloc[0:kama_window] = price.iloc[0:kama_window]
        for i in range(kama_window, len(df)):
            kama.iloc[i] = kama.iloc[i-1] + smoothing_constant.iloc[i] * (price.iloc[i] - kama.iloc[i-1])
        # TsEntropy: entropy of rolling returns
        rets = kama.pct_change().fillna(0)
        sub = sub_window
        entropy = pd.Series(np.nan, index=df.index)
        for i in range(sub, len(df)):
            chunk = rets.iloc[i-sub+1:i+1]
            chunk = chunk[chunk != 0]
            if len(chunk) > 1:
                bins = np.histogram(chunk, bins=10, density=True)[0]
                bins = bins[bins > 0]
                entropy.iloc[i] = -np.sum(bins * np.log(bins))
            else:
                entropy.iloc[i] = 0
        condition = entropy > 0
        returns = df['close'].pct_change()
        cs_returns = (returns - returns.mean()) / (returns.std() + 1e-9)
        signal = pd.Series(np.where(condition, cs_returns, -cs_returns), index=df.index)
        # Normalize A: Rolling Rank
        param = max(window, sub_window)
        rank_signal = signal.rolling(param).rank(pct=True)
        normalized = (rank_signal * 2) - 1
        return -normalized.fillna(0)

