    @staticmethod
    def alpha_factorminer_vn_142_wf(df, window=19, sub_window=5, p1=0.05):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        log_vol = np.log1p(volume)
        returns = close.pct_change().fillna(0)
        days = pd.Series(np.arange(len(df)), index=df.index)
        x_ret = days
        y_ret = returns
        cov_ret = y_ret.rolling(window).cov(x_ret)
        var_ret = x_ret.rolling(window).var().replace(0, np.nan)
        slope_ret = cov_ret / var_ret
        z_vol = (log_vol - log_vol.rolling(23).median()) / (log_vol.rolling(23).mad() + 1e-9)
        reg_resi = slope_ret * z_vol
        y_resi = reg_resi
        cov_resi = y_resi.rolling(sub_window).cov(days)
        var_resi = days.rolling(sub_window).var().replace(0, np.nan)
        raw = cov_resi / var_resi
        # Normalization E: Winsorized Fisher
        p2 = sub_window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        denom = (high - low + 1e-9)
        norm = np.arctanh(((winsorized - low) / denom) * 1.98 - 0.99)
        sig = norm.replace([np.inf, -np.inf], np.nan).fillna(0)
        return sig.clip(-1, 1)

    @staticmethod
    def alpha_factorminer_vn_143_rank(df, window=20, sub_window=10):
        close = df['close']
        returns = close.pct_change()
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        # KAMA(amt, 13)
        amt = amount
        er_span = 13
        price_change = amt.diff(er_span).abs()
        volatility = amt.diff().abs().rolling(er_span).sum()
        er = price_change / volatility.replace(0, np.nan)
        er = er.fillna(0)
        sc = (er * (2.0/3.0 - 2.0/31.0) + 2.0/31.0) ** 2
        kama = amt.copy()
        for i in range(1, len(kama)):
            if np.isnan(sc.iloc[i]):
                continue
            kama.iloc[i] = kama.iloc[i-1] + sc.iloc[i] * (amt.iloc[i] - kama.iloc[i-1])
        kama = kama.ffill()
        # MACD(close, 12, 26)
        ema12 = close.ewm(span=12, adjust=False).mean()
        ema26 = close.ewm(span=26, adjust=False).mean()
        macd_val = ema12 - ema26
        # RegResi(KAMA, MACD, 19)
        x = macd_val
        y = kama
        cov_xy = y.rolling(sub_window).cov(x)
        var_x = x.rolling(sub_window).var().replace(0, np.nan)
        beta = cov_xy / var_x
        alpha_reg = y.rolling(sub_window).mean() - beta * x.rolling(sub_window).mean()
        residuals = y - (alpha_reg + beta * x)
        # RegBeta(Residuals, returns, 11)
        x2 = returns
        y2 = residuals
        cov_xy2 = y2.rolling(window).cov(x2)
        var_x2 = x2.rolling(window).var().replace(0, np.nan)
        beta2 = cov_xy2 / var_x2
        raw = -beta2
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result.ffill().fillna(0)

