    @staticmethod
    def alpha_factorminer_vn_146_rank(df, window=5):
        high = df['high']
        low = df['low']
        close = df['close']
        ret = close.pct_change()
        vwap = df.get('vwap', (high + low + close) / 3)
        volume = df['matchingVolume']
        # Calculate CoSkew: skewness of vwap and volume over window
        vwap_roll = vwap.rolling(window)
        volume_roll = volume.rolling(window)
        coskew = ((vwap - vwap_roll.mean()) * (volume - volume_roll.mean()) ** 2).rolling(window).mean() / (vwap_roll.std() * (volume_roll.std() ** 2) + 1e-9)
        raw = ret * coskew
        # Rolling rank normalization (Case A)
        raw = raw.rolling(window).rank(pct=True) * 2 - 1
        # Corr with close over 11 periods
        corr = raw.rolling(11).corr(close)
        signal = -corr
        signal = signal.ffill().fillna(0)
        return -signal

    @staticmethod
    def alpha_factorminer_vn_146_tanh(df, window=5):
        high = df['high']
        low = df['low']
        close = df['close']
        ret = close.pct_change()
        vwap = df.get('vwap', (high + low + close) / 3)
