        raw = ret * coskew
        # Rolling Z-Score Clip (Case C)
        raw_mean = raw.rolling(window).mean()
        raw_std = raw.rolling(window).std()
        raw_z = ((raw - raw_mean) / (raw_std + 1e-9)).clip(-1, 1)
        corr = raw_z.rolling(11).corr(close)
        signal = -corr
        signal = signal.ffill().fillna(0)
