    @staticmethod
    def alpha_factorminer_vn_146_wf(df, window=70, p1=0.3):
        high = df['high']
        low = df['low']
        close = df['close']
        ret = close.pct_change()
        vwap = df.get('vwap', (high + low + close) / 3)
