    @staticmethod
    def alpha_factorminer_vn_150_r(df, window=100, p1=0.9):
        high = df['high']
        low = df['low']
        close = df['close']
        cum_max = high.expanding().max().shift(1)
        numerator = cum_max - low
        denominator = (high - low).abs()
        ratio = numerator / denominator
        cs_mean = ratio.expanding().mean()
        returns = close.pct_change()
        cs_scale_returns = (returns.rolling(window).rank(pct=True) * 2) - 1
        condition = ratio > cs_mean
        signal = pd.Series(np.where(condition, cs_scale_returns, -cs_scale_returns), index=df.index)
        raw = signal
        p2 = window
        low_q = raw.rolling(p2).quantile(p1)
        high_q = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low_q, upper=high_q, axis=0)
        numerator_w = winsorized - low_q
        denominator_w = (high_q - low_q + 1e-9)
        scaled = (numerator_w / denominator_w) * 1.98 - 0.99
        scaled = scaled.clip(-0.99, 0.99)
        result = np.arctanh(scaled)
        result = pd.Series(result, index=df.index).ffill().fillna(0)
        return -result

    @staticmethod
    def alpha_factorminer_vn_151_rank(df, window=80):
        # Tính DEMA(close, 13)
        ema1 = df['close'].ewm(span=13, adjust=False).mean()
        ema2 = ema1.ewm(span=13, adjust=False).mean()
        dema = 2 * ema1 - ema2

        # RobustZScore(DEMA, 29)
        mean_dema = dema.rolling(29).mean()
        mad_dema = (dema - mean_dema).abs().rolling(29).mean()
        robust_z_dema = (dema - mean_dema) / (mad_dema + 1e-9)

        # RobustZScore(close, 29)
        mean_close = df['close'].rolling(29).mean()
        mad_close = (df['close'] - mean_close).abs().rolling(29).mean()
        robust_z_close = (df['close'] - mean_close) / (mad_close + 1e-9)

        # Sub = robust_z_dema - robust_z_close
        raw = robust_z_dema - robust_z_close

        # Rolling Rank normalization - Trường hợp A
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_151_tanh(df, factor=5):
        # Tính DEMA(close, 13)
        ema1 = df['close'].ewm(span=13, adjust=False).mean()
        ema2 = ema1.ewm(span=13, adjust=False).mean()
        dema = 2 * ema1 - ema2

