    @staticmethod
    def alpha_factorminer_vn_151_wf(df, p1=0.1):
        p2 = 20  # hardcode window cho winsorized
        # Tính DEMA(close, 13)
        ema1 = df['close'].ewm(span=13, adjust=False).mean()
        ema2 = ema1.ewm(span=13, adjust=False).mean()
        dema = 2 * ema1 - ema2

        # RobustZScore(DEMA, 29)
        mean_dema = dema.rolling(29).mean()
        mad_dema = (dema - mean_dema).abs().rolling(29).mean()
        robust_z_dema = (dema - mean_dema) / (mad_dema + 1e-9)

        # RobustZScore(close, 29)
        mean_close = df['close'].rolling(29).mean()
        mad_close = (df['close'] - mean_close).abs().rolling(29).mean()
        robust_z_close = (df['close'] - mean_close) / (mad_close + 1e-9)

        # Sub = robust_z_dema - robust_z_close
        raw = robust_z_dema - robust_z_close

        # Winsorized Fisher normalization - Trường hợp E
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        denominator = (high - low + 1e-9)
        normalized = np.arctanh(((winsorized - low) / denominator) * 1.98 - 0.99)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_152_rank(df, window=10, sub_window=7):
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        x_reg = pd.Series(np.arange(len(df)), index=df.index)
        cov = amount.rolling(window).cov(x_reg)
        var_x = x_reg.rolling(window).var().replace(0, np.nan)
        slope_reg = cov / var_x
        # Residual: actual - predicted (predicted = intercept + slope * x, intercept = mean(actual) - slope * mean(x))
        mean_actual = amount.rolling(window).mean()
        mean_x = x_reg.rolling(window).mean()
        intercept = mean_actual - slope_reg * mean_x
        predicted = intercept + slope_reg * x_reg
        residual = amount - predicted
        # Second slope on residual
        cov2 = residual.rolling(sub_window).cov(x_reg)
        var_x2 = x_reg.rolling(sub_window).var().replace(0, np.nan)
        slope_resid = cov2 / var_x2
        raw = -slope_resid
        # Normalization A: Rolling Rank
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result.fillna(0)

