        cs_mean_ulcer = ulcer.rolling(window).mean()
        ret = df['close'].pct_change()
        raw = pd.Series(np.where(ulcer > cs_mean_ulcer, (ret - ret.rolling(window).mean()) / ret.rolling(window).std(), -((ret - ret.rolling(window).mean()) / ret.rolling(window).std())), index=df.index)
        raw = raw.ffill().fillna(0)
        result = -(-raw)
        normalized = ((result.rolling(window).rank(pct=True) * 2) - 1).fillna(0)
        return -normalized

