    @staticmethod
    def alpha_factorminer_vn_156_sign(df, window=75):
        close = df['close']
        volume = df['matchingVolume']
        # HMA(volume, 13)
        window2 = window // 2
        sqrt_window = int(np.sqrt(window))
        wma1 = volume.rolling(window2, min_periods=1).mean() * 2
        wma2 = volume.rolling(window, min_periods=1).mean()
        hma_value = 2 * wma1.rolling(window, min_periods=1).mean() - wma2.rolling(window, min_periods=1).mean()
        half_len = window // 2
        sqrt_len = int(np.sqrt(window))
        wma_half = volume.rolling(half_len, min_periods=1).apply(lambda x: np.sum(x * np.arange(1, len(x)+1)) / np.sum(np.arange(1, len(x)+1)), raw=True)
        wma_full = volume.rolling(window, min_periods=1).apply(lambda x: np.sum(x * np.arange(1, len(x)+1)) / np.sum(np.arange(1, len(x)+1)), raw=True)
        raw_hma = 2 * wma_half - wma_full
        hma = raw_hma.rolling(sqrt_len, min_periods=1).apply(lambda x: np.sum(x * np.arange(1, len(x)+1)) / np.sum(np.arange(1, len(x)+1)), raw=True)
        lookback_reg = 19
        x = hma
        y = close
        x_mean = x.rolling(lookback_reg, min_periods=lookback_reg).mean()
        y_mean = y.rolling(lookback_reg, min_periods=lookback_reg).mean()
        cov = x.rolling(lookback_reg, min_periods=lookback_reg).cov(y)
        var_x = x.rolling(lookback_reg, min_periods=lookback_reg).var()
        beta = cov / var_x.replace(0, np.nan)
        alpha_reg = y_mean - beta * x_mean
        resid = y - (beta * x + alpha_reg)
        slope_lookback = 7
        days = pd.Series(np.arange(len(df)), index=df.index)
        y_slope = resid
        x_slope = days
        x_mean_slope = x_slope.rolling(slope_lookback, min_periods=slope_lookback).mean()
        y_mean_slope = y_slope.rolling(slope_lookback, min_periods=slope_lookback).mean()
        cov_slope = (x_slope - x_mean_slope).rolling(slope_lookback, min_periods=slope_lookback).sum() * (y_slope - y_mean_slope).rolling(slope_lookback, min_periods=slope_lookback).sum() / slope_lookback
        var_x_slope = (x_slope - x_mean_slope).rolling(slope_lookback, min_periods=slope_lookback).sum() ** 2 / slope_lookback
        slope = cov_slope / var_x_slope.replace(0, np.nan)
        raw = -slope
        # Normalize: Sign/Binary Soft (D)
        result = pd.Series(np.sign(raw), index=df.index)
        return -result.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_156_wf(df, window=60, quantile_param=0.1):
        close = df['close']
        volume = df['matchingVolume']
        # HMA(volume, 13)
        window2 = window // 2
        sqrt_window = int(np.sqrt(window))
        wma1 = volume.rolling(window2, min_periods=1).mean() * 2
