        wma_full = volume.rolling(window, min_periods=1).apply(lambda x: np.sum(x * np.arange(1, len(x)+1)) / np.sum(np.arange(1, len(x)+1)), raw=True)
        raw_hma = 2 * wma_half - wma_full
        hma = raw_hma.rolling(sqrt_len, min_periods=1).apply(lambda x: np.sum(x * np.arange(1, len(x)+1)) / np.sum(np.arange(1, len(x)+1)), raw=True)
        lookback_reg = 19
        x = hma
        y = close
        x_mean = x.rolling(lookback_reg, min_periods=lookback_reg).mean()
        y_mean = y.rolling(lookback_reg, min_periods=lookback_reg).mean()
        cov = x.rolling(lookback_reg, min_periods=lookback_reg).cov(y)
        var_x = x.rolling(lookback_reg, min_periods=lookback_reg).var()
        beta = cov / var_x.replace(0, np.nan)
        alpha_reg = y_mean - beta * x_mean
        resid = y - (beta * x + alpha_reg)
        slope_lookback = 7
        days = pd.Series(np.arange(len(df)), index=df.index)
