        x_slope = days
        x_mean_slope = x_slope.rolling(slope_lookback, min_periods=slope_lookback).mean()
        y_mean_slope = y_slope.rolling(slope_lookback, min_periods=slope_lookback).mean()
        cov_slope = (x_slope - x_mean_slope).rolling(slope_lookback, min_periods=slope_lookback).sum() * (y_slope - y_mean_slope).rolling(slope_lookback, min_periods=slope_lookback).sum() / slope_lookback
        var_x_slope = (x_slope - x_mean_slope).rolling(slope_lookback, min_periods=slope_lookback).sum() ** 2 / slope_lookback
        slope = cov_slope / var_x_slope.replace(0, np.nan)
        raw = -slope
        # Normalize: Winsorized Fisher (E)
        p2 = window
        p1 = quantile_param
        low = raw.rolling(p2, min_periods=1).quantile(p1)
        high = raw.rolling(p2, min_periods=1).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        result = normalized.fillna(0)
        return -result

