    @staticmethod
    def alpha_factorminer_vn_163_rank(df, window=70, sub_window=5):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        close = df['close']
        # Decay($vwap, 11): Exponential moving average-like decay
        decay_alpha = 2.0 / (window + 1)
        decayed_vwap = vwap.ewm(alpha=decay_alpha, adjust=False).mean()
        # RegResi(decayed_vwap, close, 17): Residual of regression close on decayed_vwap
        y = close
        x = decayed_vwap
        w = 17
        cov = x.rolling(w).cov(y)
        var = x.rolling(w).var().replace(0, np.nan)
        slope = cov / var
        intercept = y.rolling(w).mean() - slope * x.rolling(w).mean()
        resid = y - (slope * x + intercept)
        # TsLinRegSlope(resid, 5): Time-series regression slope of resid over 5 periods
        days = pd.Series(np.arange(len(df)), index=df.index)
        x_days = days
        y_resid = resid
        w_slope = sub_window
        cov_slope = x_days.rolling(w_slope).cov(y_resid)
        var_slope = x_days.rolling(w_slope).var().replace(0, np.nan)
        ts_slope = cov_slope / var_slope
        # Neg(Neg(...)) = double negation => positive signal (original is Neg(Neg(x)) = x)
        raw = ts_slope
        # Normalize by rolling rank (A)
        normalized = (raw.rolling(window=window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

