        x = cumamt
        cov = y.rolling(window).cov(x)
        var = x.rolling(window).var().replace(0, np.nan)
        raw = cov / var
        # Chuẩn hóa Sign/Binary Soft
        signal = np.sign(raw)
        signal = pd.Series(signal, index=df.index).ffill().fillna(0)
