    @staticmethod
    def alpha_factorminer_vn_175_rank(df, kama_window=1, norm_window=30):
        close = df['close']
        returns = close.pct_change().fillna(0)
        kama_alpha = 2.0 / (kama_window + 1.0)
        kama = returns.ewm(alpha=kama_alpha, adjust=False).mean()
        median = kama.rolling(norm_window).median()
        mad = (kama - median).abs().rolling(norm_window).median()
        robust_z = (kama - median) / (mad * 1.4826 + 1e-9)
        signal = (-robust_z).rolling(norm_window).rank(pct=True) * 2 - 1
        return -signal.fillna(0).clip(-1, 1)

