    @staticmethod
    def alpha_factorminer_vn_179_rank(df, window=15):
        ret = df['close'].pct_change().fillna(0)
        wma_13 = ret.rolling(window=13, min_periods=1).mean()
        ret_series = ret.copy()
        wma_series = wma_13.copy()
        n = window
        demean_ret = ret_series - ret_series.rolling(n, min_periods=1).mean()
        demean_wma = wma_series - wma_series.rolling(n, min_periods=1).mean()
        num = (demean_ret * demean_wma).rolling(n, min_periods=1).sum()
        denom_ret = (demean_ret ** 2).rolling(n, min_periods=1).sum()
        denom_wma = (demean_wma ** 2).rolling(n, min_periods=1).sum()
        var_ret = denom_ret / n
        var_wma = denom_wma / n
        corr = num / ((denom_ret * denom_wma).replace(0, np.nan) ** 0.5 + 1e-9)
        coskew = (corr ** 3) * np.sqrt(1 - corr ** 2)  # approximate, simpler
        mask = ret > 0
        alpha_raw = pd.Series(np.where(mask, coskew, -coskew), index=df.index)
        alpha_raw = alpha_raw.fillna(0)
        rank_alpha = alpha_raw.rolling(window=window, min_periods=1).rank(pct=True) * 2 - 1
        return rank_alpha

