    @staticmethod
    def alpha_factorminer_vn_183_rank(df, window=100, sub_window=7):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        ret = (close - close.shift(1)) / close.shift(1).replace(0, np.nan)
        ret = ret.fillna(0)
        # CoSkew = skewness of volume weighted returns over window
        # Using rolling covariance with volume as weight simplified: co_skew ~ rolling correlation of ret and volume^3? Not standard.
        # Instead: compute rolling third central moment standardized: CoSkew(ret, vol) = E[(ret * vol)^3] / (E[(ret*vol)^2])^1.5
        w = window
        rv = ret * volume
        rv_mean = rv.rolling(w).mean()
        rv_centered = rv - rv_mean
        # third moment
        third = (rv_centered ** 3).rolling(w).mean()
        # second moment
        second = (rv_centered ** 2).rolling(w).mean().replace(0, np.nan)
        co_skew = third / (second ** 1.5)
        # RegBeta ret on volume
        w2 = sub_window
        cov = ret.rolling(w2).cov(volume)
        var_vol = volume.rolling(w2).var().replace(0, np.nan)
        beta = cov / var_vol
        # IfElse: if co_skew > 0 then beta else -beta
        cond = co_skew > 0
        raw = pd.Series(np.where(cond, beta, -beta), index=df.index).fillna(0)
        # Apply Neg (negative)
        raw = -raw
        # Normalize A: Rolling Rank
        norm = (raw.rolling(window).rank(pct=True) * 2) - 1
        return norm.fillna(0)

