    @staticmethod
    def alpha_factorminer_vn_186_wf(df, window=20, quantile=0.1):
        high = df['high']
        low = df['low']
        close = df['close']
        product = high * low
        cov = product.rolling(window).cov(close)
        var = close.rolling(window).var().replace(0, np.nan)
        slope = cov / var
        residual = product - slope * close
        neg_residual = -residual
        # Winsorized Fisher (E)
        low_q = neg_residual.rolling(window).quantile(quantile)
        high_q = neg_residual.rolling(window).quantile(1 - quantile)
        winsorized = neg_residual.clip(lower=low_q, upper=high_q, axis=0)
        # Fisher transform
        scaled = (winsorized - low_q) / (high_q - low_q + 1e-9)
        normalized = np.arctanh(scaled * 1.98 - 0.99)
        return normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_187_rank(df, window_a=30):
        close = df['close']
        high = df['high']
        low = df['low']
        # Calculate ATR over 7 periods
        tr1 = high - low
        tr2 = (high - close.shift(1)).abs()
        tr3 = (low - close.shift(1)).abs()
        tr = pd.concat([tr1, tr2, tr3], axis=1).max(axis=1)
        atr = tr.rolling(7).mean()
        # TsRank(ATR, 13)
        atr_rank = atr.rolling(window_a).rank(pct=True)
        # TsRank(close, 13)
        close_rank = close.rolling(window_a).rank(pct=True)
        # Sub = TsRank(ATR) - TsRank(close)
        raw = atr_rank - close_rank
        # Neg twice -> raw
        raw = -(-raw)
        # Normalize via rolling rank
        demeaned = raw - raw.rolling(window_a).mean()
        abs_demeaned = demeaned.abs().rolling(window_a).mean().replace(0, np.nan)
        normalized = demeaned / abs_demeaned
        normalized = normalized.fillna(0).clip(-1, 1)
        return -normalized * 1

