    @staticmethod
    def alpha_factorminer_vn_191_wf(df, window=7, p1=0.05):
        volume = df.get('matchingVolume', df.get('volume', np.ones_like(df['close'])))
        close = df['close']
        returns = df['close'].pct_change()
        max_drawdown = returns.rolling(37).apply(lambda x: (x / x.cummax() - 1).min(), raw=True)
        raw = volume.mul(max_drawdown, axis=0).rolling(window).corr(close)
        raw = -raw
        p2 = window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        numerator = winsorized - low
        denominator = high - low
        normalized = np.arctanh(((numerator / (denominator + 1e-9)) * 1.98 - 0.99).clip(-0.9999, 0.9999))
        return normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_192_k(df, window=40, sub_window=40):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        close = df['close']
        y = close
        x = vwap
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope_close_vwap = (y.rolling(window).cov(days) / days.rolling(window).var().replace(0, np.nan))
        residual = y - (slope_close_vwap * days)
        returns = df['close'].pct_change().replace([np.inf, -np.inf], np.nan).fillna(0)
        raw = residual * (returns.rolling(sub_window).skew())
        rank_normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = rank_normalized.fillna(0).replace([np.inf, -np.inf], 0).clip(-1, 1)
        return -signal

