    def alpha_factorminer_vn_192_r(df, window=30, sub_window=40):
        # Note: p1 and p2 are hardcoded inside if required; here kept as params for clarity but only 2 allowed, so p1=0.05 hardcoded, p2=window*2
        p1_val = 0.05
