    @staticmethod
    def alpha_factorminer_vn_194_rank(df, window=95):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        # Tính CumMax: giá trị đỉnh cao nhất từ đầu đến hiện tại
        cum_max = amt.cummax()
        # Tính Max Drawdown: chênh lệch từ đỉnh rolling xuống thấp nhất trong window
        rolling_max = amt.rolling(window).max()
        drawdown = rolling_max - amt
        drawdown = drawdown.rolling(window).max()  # Max drawdown in window
        drawdown = drawdown.replace(0, np.nan).ffill().fillna(0)
        raw = cum_max / (drawdown + 1e-9)
        # Normalize A: Rolling Rank
        raw_rank = raw.rolling(window).rank(pct=True) * 2 - 1
        return -raw_rank.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_194_tanh(df, window=35):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        cum_max = amt.cummax()
        rolling_max = amt.rolling(window).max()
        drawdown = rolling_max - amt
        drawdown = drawdown.rolling(window).max()
        drawdown = drawdown.replace(0, np.nan).ffill().fillna(0)
        raw = cum_max / (drawdown + 1e-9)
        # Normalize B: Dynamic Tanh
        std = raw.rolling(window).std().replace(0, np.nan).ffill().fillna(1)
        return np.tanh(raw / std).fillna(0)

    @staticmethod
    def alpha_factorminer_vn_194_zscore(df, window=70):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
