        zscore_7 = (close - close.rolling(7).mean()) / close.rolling(7).std()
        zscore_7 = zscore_7.replace([np.inf, -np.inf], 0).fillna(0)
        cond = cumprod_ratio > 1
        raw = pd.Series(np.where(cond, zscore_7, -zscore_7), index=df.index)
        normalized = (raw.rolling(window_rank).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

