    @staticmethod
    def alpha_factorminer_vn_196_rank(df, window=60, sub_window=1):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        # BollingerRange: high - low của vwap trong window
        bollinger_high = vwap.rolling(window).max()
        bollinger_low = vwap.rolling(window).min()
        bollinger_range = bollinger_high - bollinger_low
        # TsMad: trung bình động của bollinger_range và close
        mad_bollinger = bollinger_range.rolling(sub_window).mean()
        mad_close = df['close'].rolling(sub_window).mean()
        raw = mad_bollinger - mad_close
        # Chuẩn hóa Rolling Rank A
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = signal.ffill().fillna(0)
        return -signal

