    @staticmethod
    def alpha_factorminer_vn_200_rank(df, window=75):
        delta_close = df['close'].diff(3)
        delta_volume = df['volume'].diff(3) if 'volume' in df else df['matchingVolume'].diff(3)
        if delta_volume is None:
            delta_volume = df.get('matchingVolume', pd.Series(np.nan, index=df.index)).diff(3)
        mean_c = delta_close.rolling(window).mean()
        mean_v = delta_volume.rolling(window).mean()
        cov = ((delta_close - mean_c).rolling(window).mean() * (delta_volume - mean_v).rolling(window).mean()) + (
            ((delta_close - mean_c) ** 2).rolling(window).mean()) * ((delta_volume - mean_v) ** 2).rolling(window).mean()
        std_c = delta_close.rolling(window).std(ddof=0)
        std_v = delta_volume.rolling(window).std(ddof=0)
        coskew = cov / (std_c * std_v * std_c + 1e-9)
        raw = -coskew
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

