    @staticmethod
    def alpha_factorminer_vn_207_rank(df, window=100):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        ema1 = vwap.ewm(span=13, adjust=False).mean()
        ema2 = ema1.ewm(span=13, adjust=False).mean()
        dema = 2 * ema1 - ema2
        delta_vwap = vwap.diff(3)
        n = window
        # Center estimates for co-kurtosis
        dema_mean = dema.rolling(n).mean()
        delta_mean = delta_vwap.rolling(n).mean()
        num = (dema - dema_mean).rolling(n).apply(lambda x: (x ** 3).sum(), raw=True) * (delta_vwap - delta_mean).rolling(n).apply(lambda x: x.sum(), raw=True) / n
        denom = (dema - dema_mean).rolling(n).std() ** 3 * (delta_vwap - delta_mean).rolling(n).std()
        raw = num / denom.replace(0, np.nan)
        raw = raw.fillna(0)
        normalized = ((raw - raw.rolling(window).mean()) / raw.rolling(window).std()).clip(-1, 1)
        return -normalized

