    @staticmethod
    def alpha_factorminer_vn_215_k(df, window=25):
        # 1. Tinh KAMA cho amount
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        er = (abs(amt - amt.shift(10)) / amt.diff().abs().rolling(13).sum()).replace(0, np.nan)
        sc = (er * (2.0/14.0 - 2.0/15.0) + 2.0/15.0) ** 2
        kama_amt = amt.copy()
        for i in range(1, len(amt)):
            kama_amt.iloc[i] = kama_amt.iloc[i-1] + sc.iloc[i] * (amt.iloc[i] - kama_amt.iloc[i-1])
        # 2. Tinh Skew cho KAMA
        skew = kama_amt.rolling(29).skew()
        # 3. Tinh returns
        returns = df['close'].pct_change()
        # 4. Dieu kien IfElse
        raw = pd.Series(np.where(returns > 0, skew, -skew), index=df.index)
        # 5. Neg
        result = -raw
        # 6. Xu ly NaN
        result = result.ffill().fillna(0)
        # 7. Chuan hoa Rolling Rank[-1,1]
        normalized = (result.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

