    @staticmethod
    def alpha_factorminer_vn_216_rank(df, window=5):
        delta_vol = df['matchingVolume'].diff(3).fillna(0)
        close = df['close']
        n = len(df)
        days = pd.Series(np.arange(n), index=df.index)
        close_mean = close.rolling(window).mean().fillna(method='ffill')
        close_std = close.rolling(window).std().fillna(method='ffill').replace(0, np.nan)
        vol_mean = delta_vol.rolling(window).mean().fillna(method='ffill')
        vol_std = delta_vol.rolling(window).std().fillna(method='ffill').replace(0, np.nan)
        z_close = (close - close_mean) / close_std
        z_vol = (delta_vol - vol_mean) / vol_std
        cokurt = (z_close * z_vol * z_vol * z_vol).rolling(window).mean()
        raw = -cokurt.fillna(0)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = normalized.fillna(0).replace([np.inf, -np.inf], 0)
        return -signal.rename('alpha_factorminer_vn_216_a')

