        dema7 = (2 * vol.ewm(span=7, adjust=False).mean() - vol.ewm(span=7, adjust=False).mean().ewm(span=7, adjust=False).mean())
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
