        slope = (y.rolling(window).mean() * x.rolling(window).mean() - (y * x).rolling(window).mean()) / (x.rolling(window).mean() ** 2 - (x ** 2).rolling(window).mean()).replace(0, np.nan)
        raw = -slope
        norm = ((raw.rolling(window).rank(pct=True) * 2) - 1)
        return norm.ffill().fillna(0)

