    @staticmethod
    def alpha_factorminer_vn_219_r(df, window=40, winsor_pct=0.3):
        high = df['high']
        low = df['low']
        close = df['close']
        volume = df['matchingVolume']
        amount = df.get('amount', close * volume)
        ema_vol = volume.ewm(span=11, adjust=False).mean()
        quantile_75_dema = ema_vol.rolling(window).quantile(0.75)
        quantile_25_vol = volume.rolling(window).quantile(0.25)
        condition = quantile_75_dema > quantile_25_vol
        scaled_amt = (amount - amount.rolling(window).mean()) / amount.rolling(window).std()
        raw = pd.Series(np.where(condition, scaled_amt, -scaled_amt), index=df.index)
        low_q = raw.rolling(window).quantile(winsor_pct)
        high_q = raw.rolling(window).quantile(1 - winsor_pct)
        winsorized = raw.clip(lower=low_q, upper=high_q, axis=0)
        normalized = np.arctanh(((winsorized - low_q) / (high_q - low_q + 1e-9)) * 1.98 - 0.99)
        return -normalized.ffill().fillna(0)

    @staticmethod
    def alpha_factorminer_vn_220_rank(df, window=70):
        close = df['close']
        ema1 = close.ewm(span=window, adjust=False).mean()
        ema2 = ema1.ewm(span=window, adjust=False).mean()
        dema = 2 * ema1 - ema2
        cumprod = (1 + dema / dema.shift(1)).fillna(1).cumprod()
        prod = dema * window
        raw = - (cumprod / prod)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

