    @staticmethod
    def alpha_factorminer_vn_222_rank(df, window=10):
        close = df['close']
        # Tính HMA với window = 11
        half = 11 // 2
        sqrt_len = int(11 ** 0.5)
        wma1 = close.rolling(half).mean() * 2 - close.rolling(11).mean()
        wma2 = wma1.rolling(sqrt_len).mean()
        hma_11 = wma2
        # HMA fillna forward
        hma_11 = hma_11.ffill()
        # RegResi: close ~ hma (lag 19? ý là resi của close trên HMA với 19 qh?)
        # Giả định: resid = close - HMA(close, 11) với window 19 để tính slope
        # Nhưng đề là RegResi(close, HMA(close, 11), 19) có thể hiểu là resid từ regression với 19 period
        # Ta dùng rolling 19 để tính hệ số hồi quy
        y = close
        x = hma_11
        window_resi = 19
        x_avg = x.rolling(window_resi).mean()
        y_avg = y.rolling(window_resi).mean()
        cov = ((x - x_avg) * (y - y_avg)).rolling(window_resi).mean()
        var_x = ((x - x_avg) ** 2).rolling(window_resi).mean()
        beta = cov / var_x.replace(0, np.nan)
        alpha_reg = y_avg - beta * x_avg
        resid = y - alpha_reg - beta * x
        resid = resid.ffill()
        # TsLinRegSlope(resid, 13)
        y2 = resid
        x2 = pd.Series(np.arange(len(df)), index=df.index)
        window_slope = window
        cov_slope = ((x2 - x2.rolling(window_slope).mean()) * (y2 - y2.rolling(window_slope).mean())).rolling(window_slope).mean()
        var_x_slope = ((x2 - x2.rolling(window_slope).mean()) ** 2).rolling(window_slope).mean()
        slope = cov_slope / var_x_slope.replace(0, np.nan)
        raw = -slope  # Neg
        # Rolling Rank
        result = (raw.rolling(window_slope).rank(pct=True) * 2) - 1
        result = result.ffill().fillna(0)
        return -result

    @staticmethod
    def alpha_factorminer_vn_222_tanh(df, window=30):
        close = df['close']
        # HMA 11
        half = 11 // 2
        sqrt_len = int(11 ** 0.5)
        wma1 = close.rolling(half).mean() * 2 - close.rolling(11).mean()
        wma2 = wma1.rolling(sqrt_len).mean()
        hma_11 = wma2.ffill()
        # Resi
        window_resi = 19
        x = hma_11
        y = close
        x_avg = x.rolling(window_resi).mean()
        y_avg = y.rolling(window_resi).mean()
        cov = ((x - x_avg) * (y - y_avg)).rolling(window_resi).mean()
        var_x = ((x - x_avg) ** 2).rolling(window_resi).mean()
        beta = cov / var_x.replace(0, np.nan)
        alpha_reg = y_avg - beta * x_avg
        resid = y - alpha_reg - beta * x
        resid = resid.ffill()
        # Slope
        y2 = resid
        x2 = pd.Series(np.arange(len(df)), index=df.index)
        window_slope = window
        cov_slope = ((x2 - x2.rolling(window_slope).mean()) * (y2 - y2.rolling(window_slope).mean())).rolling(window_slope).mean()
        var_x_slope = ((x2 - x2.rolling(window_slope).mean()) ** 2).rolling(window_slope).mean()
        slope = cov_slope / var_x_slope.replace(0, np.nan)
        raw = -slope
        # Dynamic Tanh
        std = raw.rolling(window_slope).std()
        result = np.tanh(raw / std.replace(0, np.nan))
        result = result.ffill().fillna(0)
        return -result

