    @staticmethod
    def alpha_factorminer_vn_223_wf(df, window=1, sub_window=10, p1=0.05):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        volume = df.get('matchingVolume', df.get('volume', 1))
        returns = df['close'].pct_change()
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        resi = amt - (volume * (amt.rolling(window).cov(volume) / volume.rolling(window).var().replace(0, np.nan)))
        skew_resi = resi.rolling(sub_window).skew()
        condition = skew_resi > 0
        z_returns = (returns - returns.rolling(sub_window).mean()) / returns.rolling(sub_window).std().replace(0, np.nan)
        z_vwap = (vwap - vwap.rolling(sub_window).mean()) / vwap.rolling(sub_window).std().replace(0, np.nan)
        signal = pd.Series(np.where(condition, z_returns, -z_vwap), index=df.index)
        signal = signal.replace([np.inf, -np.inf], np.nan).ffill().fillna(0)
        param2 = sub_window * 2
        low = signal.rolling(param2).quantile(p1)
        high = signal.rolling(param2).quantile(1 - p1)
        winsorized = signal.clip(lower=low, upper=high, axis=0)
