    @staticmethod
    def alpha_factorminer_vn_231_rank(df, window=75):
        high = df['high']
        low = df['low']
        close = df['close']
        tr = pd.concat([high - low, (high - close.shift(1).abs()), (low - close.shift(1).abs())], axis=1).max(axis=1)
        atr = tr.rolling(window=window, min_periods=window).mean()
        raw = high - low
        hilo_atr_ratio = raw / atr.replace(0, np.nan)
        delta_hilo_atr = hilo_atr_ratio.diff(3)
        neg_hilo_atr = -delta_hilo_atr
        neg_hilo_atr = neg_hilo_atr.ffill().fillna(0)
        normalized = (neg_hilo_atr.rolling(window=window).rank(pct=True) * 2) - 1
        return -normalized.replace([np.inf, -np.inf], 0).ffill().fillna(0)

