    @staticmethod
    def alpha_factorminer_vn_235_rank(df, window=90):
        _range = df['high'] - df['low']
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope = _range.rolling(window).cov(days) / days.rolling(window).var().replace(0, np.nan)
