    @staticmethod
    def alpha_factorminer_vn_239_wf(df, window=90, p1=0.1):
        high = df['high']
        low = df['low']
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = df['close'].pct_change()
        # ATR 7
        tr = pd.concat([high - low, (high - close.shift()).abs(), (low - close.shift()).abs()], axis=1).max(axis=1)
        atr_7 = tr.rolling(window).mean()
        atr_21_mean = tr.rolling(21).mean()
        condition = atr_7 > atr_21_mean
        # Beta(returns, vwap, 13)
        x = vwap
        y = returns
        cov = y.rolling(13).cov(x)
        var = x.rolling(13).var().replace(0, np.nan)
        beta = cov / var
        beta_z = (beta - beta.rolling(13).mean()) / beta.rolling(13).std()
        # Resid(returns, vwap, 13)
        intercept = y.rolling(13).mean() - beta * x.rolling(13).mean()
        resid = y - (intercept + beta * x)
        resid_z = (resid - resid.rolling(13).mean()) / resid.rolling(13).std()
        raw = pd.Series(np.where(condition, beta_z, resid_z), index=df.index)
        # Normalize E: Winsorized Fisher
        p2 = 21
        low_q = raw.rolling(p2).quantile(p1)
        high_q = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low_q, upper=high_q, axis=0)
        normalized = np.arctanh(((winsorized - low_q) / (high_q - low_q + 1e-9)) * 1.98 - 0.99)
        signal = normalized.ffill().fillna(0)
        return -signal * -1

    @staticmethod
    def alpha_factorminer_vn_240_k(df, window=30):
        ret = df['close'].pct_change()
        n = len(df)
        skew = pd.Series(np.full(n, np.nan), index=df.index)
        for i in range(window, 2 * window):
            if i <= n:
                r = ret.iloc[i - window:i]
                if len(r.dropna()) >= 3:
                    mean_r = r.mean()
                    std_r = r.std(ddof=0)
                    m3 = ((r - mean_r) ** 3).mean()
                    skew.iloc[i - 1] = m3 / (std_r ** 3) if std_r > 0 else 0
                else:
                    skew.iloc[i - 1] = 0
        vaR_series = pd.Series(np.full(n, np.nan), index=df.index)
        for i in range(window, n + 1):
            r = ret.iloc[i - window:i]
            r_sorted = r.dropna().sort_values()
            idx = int(np.floor(0.1 * len(r_sorted)))
            if idx < len(r_sorted):
                vaR_series.iloc[i - 1] = r_sorted.iloc[idx]
            else:
                vaR_series.iloc[i - 1] = 0
        raw = skew - vaR_series
        raw_rank = raw.rolling(window).rank(pct=True) * 2 - 1
        result = -raw_rank
        result = result.ffill().fillna(0)
        return result

