    @staticmethod
    def alpha_factorminer_vn_252_rank(df: pd.DataFrame, window: int = 13, decay: int = 5) -> pd.Series:
        # Tính returns (log returns để ổn định)
        close = df['close']
        returns = np.log(close / close.shift(1))
        # Volume ratio with TsMax (13 periods)
        volume = df['matchingVolume']
        volume_ratio = volume / volume.rolling(window=window, min_periods=1).max()
        # Raw alpha: returns * volume_ratio
        raw = returns * volume_ratio
        # Decay factor: sử dụng decay_linear thủ công (dạng weighted moving average) với trọng số giảm dần
        weights = np.array([2**(i) for i in range(decay, 0, -1)])
        weights = weights / weights.sum()
        # Áp dụng convolution
        decayed = raw.rolling(window=decay, min_periods=1).apply(lambda x: np.dot(x, weights[-len(x):]), raw=True)
        # Negative sign
        signal = -decayed
        # Chuẩn hóa Rolling Rank (A) - loại bỏ nhiễu
        normalized = (signal.rolling(window=window, min_periods=1).rank(pct=True) * 2) - 1
        normalized = normalized.fillna(0)
        return normalized

    @staticmethod
    def alpha_factorminer_vn_252_tanh(df: pd.DataFrame, window: int = 13, decay: int = 5) -> pd.Series:
        # Tính returns
        close = df['close']
        returns = np.log(close / close.shift(1))
        # Volume ratio
        volume = df['matchingVolume']
        volume_ratio = volume / volume.rolling(window=window, min_periods=1).max()
        raw = returns * volume_ratio
        # Decay factor
        weights = np.array([2**(i) for i in range(decay, 0, -1)])
        weights = weights / weights.sum()
        decayed = raw.rolling(window=decay, min_periods=1).apply(lambda x: np.dot(x, weights[-len(x):]), raw=True)
        signal = -decayed
        # Chuẩn hóa Dynamic Tanh - giữ cường độ
        std = signal.rolling(window=window, min_periods=1).std()
        normalized = np.tanh(signal / (std + 1e-9))
        normalized = normalized.fillna(0)
        return normalized

    @staticmethod
    def alpha_factorminer_vn_252_zscore(df: pd.DataFrame, window: int = 13, decay: int = 5) -> pd.Series:
        # Tính returns
        close = df['close']
        returns = np.log(close / close.shift(1))
        # Volume ratio
        volume = df['matchingVolume']
        volume_ratio = volume / volume.rolling(window=window, min_periods=1).max()
        raw = returns * volume_ratio
        # Decay factor
        weights = np.array([2**(i) for i in range(decay, 0, -1)])
        weights = weights / weights.sum()
        decayed = raw.rolling(window=decay, min_periods=1).apply(lambda x: np.dot(x, weights[-len(x):]), raw=True)
        signal = -decayed
        # Chuẩn hóa Rolling Z-Score/Clip - cho spread/oscillator
        mean = signal.rolling(window=window, min_periods=1).mean()
        std = signal.rolling(window=window, min_periods=1).std()
        normalized = ((signal - mean) / (std + 1e-9)).clip(-1, 1)
        normalized = normalized.fillna(0)
        return normalized

    @staticmethod
    def alpha_factorminer_vn_252_sign(df: pd.DataFrame, window: int = 13, decay: int = 5) -> pd.Series:
        # Tính returns
        close = df['close']
        returns = np.log(close / close.shift(1))
        # Volume ratio
        volume = df['matchingVolume']
        volume_ratio = volume / volume.rolling(window=window, min_periods=1).max()
        raw = returns * volume_ratio
        # Decay factor
        weights = np.array([2**(i) for i in range(decay, 0, -1)])
        weights = weights / weights.sum()
        decayed = raw.rolling(window=decay, min_periods=1).apply(lambda x: np.dot(x, weights[-len(x):]), raw=True)
        signal = -decayed
        # Chuẩn hóa Sign/Binary Soft - cho trend following
        normalized = np.sign(signal)
        normalized = pd.Series(normalized, index=df.index).fillna(0)
        return normalized

    @staticmethod
    def alpha_factorminer_vn_252_wf(df: pd.DataFrame, window: int = 13, decay: int = 5, p1: float = 0.05) -> pd.Series:
        # Tính returns
        close = df['close']
        returns = np.log(close / close.shift(1))
        # Volume ratio
        volume = df['matchingVolume']
        volume_ratio = volume / volume.rolling(window=window, min_periods=1).max()
        raw = returns * volume_ratio
        # Decay factor
        weights = np.array([2**(i) for i in range(decay, 0, -1)])
        weights = weights / weights.sum()
        decayed = raw.rolling(window=decay, min_periods=1).apply(lambda x: np.dot(x, weights[-len(x):]), raw=True)
        signal = -decayed
        # Chuẩn hóa Winsorized Fisher - cho heavy tails
        low = signal.rolling(window=window, min_periods=1).quantile(p1)
        high = signal.rolling(window=window, min_periods=1).quantile(1 - p1)
        winsorized = signal.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        normalized = normalized.fillna(0)
        return normalized

    @staticmethod
    def alpha_factorminer_vn_253_rank(df, window=80):
        returns = df['close'].pct_change().fillna(0)
        std_returns = returns.rolling(5).std().fillna(0)
        slope = std_returns.rolling(window).cov(pd.Series(np.arange(window), index=std_returns.iloc[:window].index)) / pd.Series(np.arange(window), index=std_returns.iloc[:window].index).rolling(window).var().replace(0, np.nan)
        slope = slope.fillna(method='ffill').fillna(0)
        cond = slope > 0
        delta_std = std_returns.diff(3).fillna(0)
        mean_std = std_returns.rolling(window).mean().fillna(0)
        raw = -np.where(cond, delta_std / delta_std.abs().mean(), mean_std / mean_std.abs().mean())
        raw = pd.Series(raw, index=df.index).fillna(0)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

