    @staticmethod
    def alpha_factorminer_vn_255_rank(df, window=15):
        close = df['close']
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        log_return = np.log(close / close.shift(1))
        tsmin_amt = amount.rolling(11).min()
        div_val = amount / tsmin_amt.replace(0, np.nan)
        mul_val = log_return * div_val
        decay = mul_val.rolling(window).apply(lambda x: sum(x * (1 - 1/window) ** np.arange(len(x))[::-1]), raw=True)
        neg_neg = -(-decay)
        raw = neg_neg
        norm = (raw.rolling(window).rank(pct=True) * 2) - 1
        return norm.ffill().fillna(0)

