    @staticmethod
    def alpha_factorminer_vn_264_rank(df, window=60, decay=10):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        delta_vwap = vwap.diff(2)
        std_amt = amount.rolling(window).std()
        raw = delta_vwap * (amount / std_amt.replace(0, np.nan))
        decay_weights = np.array([0.5 ** i for i in range(decay)])
        decay_weights /= decay_weights.sum()
        raw_decayed = raw.rolling(decay).apply(lambda x: np.dot(x, decay_weights[::-1]), raw=True)
        signal = (raw_decayed.rolling(decay).rank(pct=True) * 2) - 1
        return signal.fillna(0)

