    @staticmethod
    def alpha_factorminer_vn_273_rank(df, window=55):
        close = df['close']
        returns = close.pct_change().fillna(0)
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        ema7 = amt.ewm(span=7, adjust=False).mean()
        sub_amt_ema = amt - ema7
        # Rolling co-kurtosis: E[(x - μ)²(y - μ)²] / (σ_x² * σ_y²) - 1? No, using cov of squares approach
        mean_ret = returns.rolling(window=window).mean()
        std_ret = returns.rolling(window=window).std().replace(0, np.nan)
        mean_sub = sub_amt_ema.rolling(window=window).mean()
        std_sub = sub_amt_ema.rolling(window=window).std().replace(0, np.nan)
        # Co-kurtosis approximation: E[(ret - μ_ret)^2 * (sub - μ_sub)^2] / (σ_ret^2 * σ_sub^2) - 1
        ret_dev = returns - mean_ret
        sub_dev = sub_amt_ema - mean_sub
        co_kurt = (ret_dev ** 2 * sub_dev ** 2).rolling(window=window).mean() / (std_ret ** 2 * std_sub ** 2 + 1e-9) - 1
        # Z-score of co-kurtosis
        zscore = (co_kurt - co_kurt.rolling(window=window).mean()) / (co_kurt.rolling(window=window).std().replace(0, np.nan) + 1e-9)
        raw = -zscore
        raw = raw.ffill().fillna(0)
        # Normalization A: Rolling Rank
        normalized = (raw.rolling(window=window).rank(pct=True) * 2) - 1
        return normalized.ffill().fillna(0)

