    @staticmethod
    def alpha_factorminer_vn_278_8(df, window=30):
        close = df['close']
        ret = close.pct_change()
        ema7 = close.ewm(span=7, adjust=False).mean()
        std7 = close.rolling(7).std()
        x = (close - ema7) / std7.replace(0, np.nan)
        # CoSkew = 3rd central moment / (sigma^3) rolling
        mu_ret = ret.rolling(window).mean()
        mu_x = x.rolling(window).mean()
        dr = ret - mu_ret
        dx = x - mu_x
        coskew = (dr * dx).rolling(window).mean() / ((ret.rolling(window).std().replace(0, np.nan) * x.rolling(window).std().replace(0, np.nan)) ** 1.5 + 1e-9)
        raw = -coskew
        # Normalization: Rolling Z-Score (Case C) since CoSkew is a spread/oscillator-like statistic
        norm = ((raw - raw.rolling(window).mean()) / raw.rolling(window).std().replace(0, np.nan)).clip(-1, 1)
        return -norm

    @staticmethod
    def alpha_factorminer_vn_278_k(df, window=30):
        close = df['close']
