    @staticmethod
    def alpha_factorminer_vn_281_rank(df, window=40, sub_window=40):
        # Tính returns
        returns = df['close'].pct_change()
        # Std của returns với sub_window
        std_ret = returns.rolling(sub_window).std()
        # High - Low
        hl = df['high'] - df['low']
        # RegBeta: tính slope của std_ret vs hl
        # Sử dụng công thức slope: y.rolling(w).cov(x) / x.rolling(w).var()
        # y = std_ret, x = hl
        cov = std_ret.rolling(window).cov(hl)
        var_hl = hl.rolling(window).var().replace(0, np.nan)
        beta = cov / var_hl
        # Neg: nhân -1
        raw = -beta
        # Chuẩn hóa Rolling Rank (A)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        # Xử lý NaN
        normalized = normalized.ffill().fillna(0)
        return normalized

