        var_hl = hl.rolling(window).var().replace(0, np.nan)
        beta = cov / var_hl
        raw = -beta
        # Chuẩn hóa Dynamic Tanh (B)
        std_raw = raw.rolling(window).std().replace(0, np.nan)
        normalized = np.tanh(raw / std_raw)
        normalized = normalized.ffill().fillna(0)
        return normalized

