        delta_neg = -delta_close_2
        cs_zscore_2 = (delta_neg - delta_neg.expanding().mean()) / delta_neg.expanding().std()
        raw = pd.Series(np.where(cond, cs_zscore_1, cs_zscore_2), index=df.index)
