    @staticmethod
    def alpha_factorminer_vn_290_zscore(df, window=30):
        close = df['close']
        macd_line = close.ewm(span=12, adjust=False).mean() - close.ewm(span=26, adjust=False).mean()
        delta_close_3 = close.diff(3)
        condition = macd_line > 0
        raw = pd.Series(
            np.where(condition, delta_close_3, -delta_close_3),
            index=df.index
        )
        mean_ = raw.rolling(window).mean()
        std_ = raw.rolling(window).std()
        normalized = ((raw - mean_) / (std_ + 1e-9)).clip(-1, 1)
        return normalized.fillna(0)

