    @staticmethod
    def alpha_factorminer_vn_291_k(df, window=25):
        volume = df['matchingVolume']
        returns = df['close'].pct_change()
        # SumIf: volume when returns > 0 (last 3 periods)
        volume_vol_up = volume * (returns > 0).astype(int)
        sum_up = volume_vol_up.rolling(3).sum()
        volume_vol_down = volume * (returns < 0).astype(int)
        sum_down = volume_vol_down.rolling(3).sum()
        diff = (sum_up - sum_down) / volume.rolling(window).mean().replace(0, np.nan)
        diff = diff.ffill().fillna(0)
        result = (diff.rolling(window).rank(pct=True) * 2) - 1
        return result.fillna(0)

