    @staticmethod
    def alpha_factorminer_vn_293_rank(df, window=35):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        returns = close.pct_change()
        corr_vol_ret = volume.rolling(window).corr(returns)
        x = pd.Series(np.arange(len(df)), index=df.index)
        slope_close = close.rolling(window).cov(x) / x.rolling(window).var().replace(0, np.nan)
        linreg_slope = slope_close
        neg_linreg_slope = -linreg_slope
        cszscore_linreg = (linreg_slope - linreg_slope.expanding().mean()) / linreg_slope.expanding().std().replace(0, np.nan)
        cszscore_neg = (neg_linreg_slope - neg_linreg_slope.expanding().mean()) / neg_linreg_slope.expanding().std().replace(0, np.nan)
        raw = np.where(corr_vol_ret > 0, cszscore_linreg, cszscore_neg)
        raw = pd.Series(raw, index=df.index)
        # Chuẩn hóa Rolling Rank
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        result = result.ffill().fillna(0)
        return result

