    @staticmethod
    def alpha_factorminer_vn_295_rank(df, window=7, sub_window=11):
        close = df['close']
        amt = df.get('amount', close * df.get('matchingVolume', df.get('volume', 1)))
        returns = close.pct_change()
        std_amt = amt.rolling(window).std()
        mean_std_amt = std_amt.rolling(21).mean()
        cond = std_amt > mean_std_amt
        # CoSkew and CoKurt using rolling covariances
        mean_amt = amt.rolling(sub_window).mean()
        mean_ret = returns.rolling(sub_window).mean()
        # Central moments
        m2_aa = ((amt - mean_amt) ** 2).rolling(sub_window).mean()
        m2_rr = ((returns - mean_ret) ** 2).rolling(sub_window).mean()
        m2_ar = ((amt - mean_amt) * (returns - mean_ret)).rolling(sub_window).mean()
        m3_ar = ((amt - mean_amt) * ((returns - mean_ret) ** 2)).rolling(sub_window).mean()
        m4_ar = ((amt - mean_amt) * ((returns - mean_ret) ** 3)).rolling(sub_window).mean()
        # CoSkew = m3_ar / (std_amt * std_ret^2)
        std_ret = returns.rolling(sub_window).std()
        coskew = m3_ar / (std_amt.rolling(sub_window).mean() * (std_ret ** 2) + 1e-9)
        # CoKurt = m4_ar / (std_amt * std_ret^3)
        cokurt = m4_ar / (std_amt.rolling(sub_window).mean() * (std_ret ** 3) + 1e-9)
        # CsScale: cross-sectional rank => pct rank with rolling
        def alpha_factorminer_vn_295_rank(series):
            return series.rolling(window).rank(pct=True)
        coskew_scaled = cs_scale(coskew.fillna(0))
        cokurt_scaled = cs_scale(cokurt.fillna(0))
        raw = pd.Series(np.where(cond, coskew_scaled, cokurt_scaled), index=df.index)
        # Negate
        raw = -raw
        # Normalize to [-1, 1] via rolling rank
        result = (raw.rolling(window ** 2).rank(pct=True) * 2 - 1)
        return result

