    @staticmethod
    def alpha_factorminer_vn_298_wf(df, window=70, rank_window=5, p1=0.05):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        div_amt_close = amount / df['close']
        vwap_rank = vwap.rolling(rank_window).rank()
