    @staticmethod
    def alpha_factorminer_vn_308_rank(df, window=20):
        close = df['close']
        returns = close.pct_change().fillna(0)
        delta_close = close.diff().fillna(0)
        # TsEntropy: -sum(p * log(p)) với p là xác suất trong rolling window
        # Sử dụng rolling apply với vectorized tính p nhưng không dùng apply -> dùng công thức xấp xỉ
        # Thay bằng: sử dụng rolling rank để ước lượng entropy
        rank_ret = returns.rolling(window).rank(pct=True).fillna(0.5).clip(0.001, 0.999)
        entropy_ret = -(rank_ret * np.log(rank_ret) + (1 - rank_ret) * np.log(1 - rank_ret))
        rank_delta = delta_close.rolling(window).rank(pct=True).fillna(0.5).clip(0.001, 0.999)
        entropy_delta = -(rank_delta * np.log(rank_delta) + (1 - rank_delta) * np.log(1 - rank_delta))
        raw = entropy_ret - entropy_delta
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_308_tanh(df, window=20):
        close = df['close']
        returns = close.pct_change().fillna(0)
        delta_close = close.diff().fillna(0)
        rank_ret = returns.rolling(window).rank(pct=True).fillna(0.5).clip(0.001, 0.999)
        entropy_ret = -(rank_ret * np.log(rank_ret) + (1 - rank_ret) * np.log(1 - rank_ret))
        rank_delta = delta_close.rolling(window).rank(pct=True).fillna(0.5).clip(0.001, 0.999)
        entropy_delta = -(rank_delta * np.log(rank_delta) + (1 - rank_delta) * np.log(1 - rank_delta))
        raw = entropy_ret - entropy_delta
        normalized = np.tanh(raw / raw.rolling(window).std().replace(0, np.nan))
        return normalized.fillna(0)

