    @staticmethod
    def alpha_factorminer_vn_308_wf(df, window=80, p1=0.1):
        close = df['close']
        returns = close.pct_change().fillna(0)
        delta_close = close.diff().fillna(0)
        rank_ret = returns.rolling(window).rank(pct=True).fillna(0.5).clip(0.001, 0.999)
        entropy_ret = -(rank_ret * np.log(rank_ret) + (1 - rank_ret) * np.log(1 - rank_ret))
        rank_delta = delta_close.rolling(window).rank(pct=True).fillna(0.5).clip(0.001, 0.999)
        entropy_delta = -(rank_delta * np.log(rank_delta) + (1 - rank_delta) * np.log(1 - rank_delta))
        raw = entropy_ret - entropy_delta
        p2 = window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_309_9(df, window=25):
        returns = df['close'].pct_change()
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        amount_log = np.log1p(amount)

        # Compute Beta for current price returns vs amount
        cov = returns.rolling(window).cov(amount_log)
        var_amount = amount_log.rolling(window).var().replace(0, np.nan)
        beta = cov / var_amount

        # Compute rolling median of beta
        median_beta = beta.rolling(window).median()

        # Condition: if beta > median_beta, use Beta Residuals, else use Beta itself
        # RegResi: residuals from regression of returns on amount
        # For simplicity: resi = returns - (beta * amount_log + intercept)
        # We'll compute intercept via mean
        rolling_mean_returns = returns.rolling(window).mean()
        rolling_mean_amount = amount_log.rolling(window).mean()
        intercept = rolling_mean_returns - beta * rolling_mean_amount
        resid = returns - (beta * amount_log + intercept)

        # Compute Z-score of residuals (condition True) and Z-score of beta (condition False)
        zscore_resid = (resid - resid.rolling(window).mean()) / resid.rolling(window).std().replace(0, np.nan)
        zscore_beta = (beta - beta.rolling(window).mean()) / beta.rolling(window).std().replace(0, np.nan)

        # Conditional selection
        signal = pd.Series(np.where(beta > median_beta, zscore_resid, zscore_beta), index=df.index)
        signal = signal.ffill().fillna(0)

        # Final normalization to [-1,1] using tanh
        return np.tanh(signal)

    @staticmethod
    def alpha_factorminer_vn_309_rank(df, window=100):
        # Calculate returns
        ret = df['close'].pct_change()
        # Calculate amount, using fallback
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        # Calculate Beta(amount, returns, window) using formula: covariance/variance
        amt_ret_cov = amount.rolling(window).cov(ret)
        ret_var = ret.rolling(window).var().replace(0, np.nan)
        beta_amt_ret = amt_ret_cov / ret_var
        # Calculate CsMedian of Beta over window
        cs_median_beta = beta_amt_ret.rolling(window).median()
        # Condition: Beta > CsMedian of Beta
        cond = beta_amt_ret > cs_median_beta
        # If cond True: CsZScore(RegResi($returns, $amt, 17))
        # RegResi = residuals of regression returns ~ amount
        # slope = covariance/variance of amount
        amt_var = amount.rolling(window).var().replace(0, np.nan)
        slope_reg = amt_ret_cov / amt_var
        # predicted ret = slope * amount
        predicted_ret = slope_reg * amount
        residual = ret - predicted_ret
        # CsZScore of residual over window
        z_residual = (residual - residual.rolling(window).mean()) / residual.rolling(window).std().replace(0, np.nan)
        # If cond False: CsZScore(RegBeta($returns, $amt, 17))
        # RegBeta = beta of returns ~ amount => use slope_reg
        z_beta = (slope_reg - slope_reg.rolling(window).mean()) / slope_reg.rolling(window).std().replace(0, np.nan)
        # Combine
        raw = pd.Series(np.where(cond, z_residual, z_beta), index=df.index)
        # Normalize using Rolling Rank (A)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        # Negate
        result = -normalized
        # Fill NaN
        result = result.ffill().fillna(0)
        return -result

