    @staticmethod
    def alpha_factorminer_vn_310_rank(df, window=10, sub_window=70):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = df['close'].pct_change()
        std_amt = amt.rolling(window=window).std()
        median_std_amt = std_amt.rolling(window=sub_window).median()
        # Tính RegResi và RegBeta
        x = amt
        y = returns
        w = 7
        days = pd.Series(np.arange(len(df)), index=df.index)
        # RegResi: y - (slope * x + intercept)
        cov = y.rolling(w).cov(x)
        var_x = x.rolling(w).var().replace(0, np.nan)
        slope = cov / var_x
        intercept = y.rolling(w).mean() - slope * x.rolling(w).mean()
        reg_resi = y - (slope * x + intercept)
        # RegBeta: cov / var_x
        reg_beta = cov / var_x
        raw = pd.Series(np.where(std_amt > median_std_amt, reg_resi, reg_beta), index=df.index)
        raw = -raw
        normalized = (raw.rolling(window=window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

